  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","locale":"en","product_id":"seoul-suwon-hwaseong-folk-village-starfield-library","seo":{"pageTitle":"Suwon Hwaseong, Folk Village & Starfield Library | AtoC Korea","metaDescription":"10-hour small-group day tour from Seoul: UNESCO Suwon Hwaseong Fortress, Hwaseong Haenggung Palace, Korean Folk Village (Yongin), and Starfield Suwon Library.","primaryKeywords":["Suwon Hwaseong tour from Seoul","Korean Folk Village day trip","Starfield Library Suwon tour","UNESCO Korea day tour"],"ogImage":"https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"Suwon Hwaseong, Korean Folk Village & Starfield Library Day Tour from Seoul | AtoC Korea"},"catalog_card":{"thumbnail":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"Suwon: Hwaseong, Folk Village & Starfield","priceLabel":"From US$60 per person (was $66, 9% off)","shortCardDescription":"A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed Suwon Hwaseong Fortress (18th-century walls and gates), the restored Hwaseong Haenggung Palace with its Joseon-era reenactments, the immersive open-air Korean Folk Village in Yongin, and the dramatic four-floor Starfield Library Suwon. 10 hours with included transport and admissions.","tags":["small_group","culture","unesco","heritage","library","folk_village","day_trip"],"rating":0,"reviewCount":0,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","subtitle":"A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed…","region":"Gyeonggi-do (south of Seoul)","duration":"10 hours","stopsCount":6,"badges":["Small Group","Culture","UNESCO","Heritage","Library","Folk Village","Day Trip"],"heroImage":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp"},"headlineLine1":"Suwon Heritage Day","headlineLine2":"Hwaseong, Folk Village & Starfield","price":{"amountLabel":"60","currency":"USD","per":"person","salePriceUsd":60,"originalPriceUsd":66,"discountPercent":9},"hero":{"imageUrl":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","imagePosition":"center 35%","tagline":"Korea''s only walled fortress city built with its original Uigwe records, a folk village, and the library that''s all over Instagram","pills":["Small Group","Culture"],"meta":{"duration":"10 hours","region":"Gyeonggi-do (south of Seoul)","stops":"6 stops","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"camera","label":"Photo Value","value":"Excellent","level":5},{"icon":"mountain","label":"Scenic","value":"Good","level":4},{"icon":"footprints","label":"Walking","value":"High","level":4},{"icon":"cloud-rain","label":"Rain Safety","value":"Good","level":4},{"icon":"users","label":"Family Fit","value":"Good","level":4},{"icon":"gauge","label":"Balance","value":"Balanced","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 1","caption":"Suwon Hwaseong Fortress — photo 1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"Korean Folk Village (Yongin)","alt":"Korean Folk Village (Yongin) — gallery image 1","caption":"Korean Folk Village (Yongin) — photo 1"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield Library Suwon","alt":"Starfield Library Suwon — gallery image 1","caption":"Starfield Library Suwon — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 2","caption":"Suwon Hwaseong Fortress — photo 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 3","caption":"Suwon Hwaseong Fortress — photo 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 4","caption":"Suwon Hwaseong Fortress — photo 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 5","caption":"Suwon Hwaseong Fortress — photo 5"},{"id":8,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Suwon Hwaseong Fortress","alt":"Suwon Hwaseong Fortress — gallery image 6","caption":"Suwon Hwaseong Fortress — photo 6"},{"id":9,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"Korean Folk Village (Yongin)","alt":"Korean Folk Village (Yongin) — gallery image 2","caption":"Korean Folk Village (Yongin) — photo 2"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield Library Suwon","alt":"Starfield Library Suwon — gallery image 2","caption":"Starfield Library Suwon — photo 2"},{"id":11,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield Library Suwon","alt":"Starfield Library Suwon — gallery image 3","caption":"Starfield Library Suwon — photo 3"},{"id":12,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield Library Suwon","alt":"Starfield Library Suwon — gallery image 4","caption":"Starfield Library Suwon — photo 4"}],"itineraryStops":[{"number":1,"time":"≈ 08:00","duration":"10 min","name":"Seoul departure","category":"Pickup & departure","description":"Pickup from one of two central Seoul meeting points: **Hongik University Station Exit 8** (Hongdae area, Seoul Subway Line 2/Airport Express) or **Myeongdong Station Exit 2 or 4** (Seoul Subway Line 4). Confirm exact pickup time and location at booking — the schedule is built around an early start to reach Hwaseong Fortress before the late-morning Korean tour-group rush. \n\nAbout **1 hour by coach south to Suwon** via the Gyeongbu Expressway — the historical fortress city of Joseon''s King Jeongjo, who built Hwaseong (1794-1796) to honor and protect the tomb of his executed father Crown Prince Sado. Light traffic Mon-Fri morning; weekend traffic adds 15-20 min cushion. Coach is air-conditioned and equipped with USB charging at most seats.","highlights":["Pickup from Hongik University (Line 2) or Myeongdong (Line 4) ~08:00","1-hour coach south to Suwon via Gyeongbu Expressway","Coach with air conditioning + USB charging","Designed for early arrival at Hwaseong Fortress before tour-group rush"],"timeUsed":["Meet at designated Seoul pickup point (~5 min for boarding)","1-hour coach drive to Suwon (~60 min in light traffic)"],"whyOnRoute":"An 09:00 Seoul departure puts the group at Hwaseong Fortress before midday crowds and aligns with Korean Folk Village''s afternoon performance schedule (Hanbok wedding ceremony reenactment, equestrian show, Nong-ak farmers'' percussion).","visitBasics":{},"convenience":{},"smartNotes":{"tip":"Confirm exact pickup time and meeting point at booking — Seoul morning rush hour (07:00-09:00) makes punctuality critical. Bring water, sunscreen, and comfortable shoes for the fortress wall walking."},"_poi_meta":{"poi_key":"OPS_seoul_pickup_default","verified":false,"match":"operational_default","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational pickup — Seoul departure; not a sightseeing POI"},"_role":"pickup"},{"number":2,"time":"≈ 09:30","duration":"75 min","name":"Suwon Hwaseong Fortress","category":"UNESCO Fortress","description":"**Suwon Hwaseong (수원화성) — UNESCO World Heritage Site since 1997** — is Korea''s only walled fortress city preserved with its original 10-volume construction record (Hwaseong Seongyeok Uigwe, separately inscribed on the UNESCO Memory of the World Register in 2007). Built **1794-1796 in just 2 years 9 months** under King Jeongjo (정조, 22nd Joseon king, r. \n\n1776-1800), Hwaseong was the king''s project to relocate the Joseon capital from Hanyang (Seoul) to Suwon — and to honor his father Crown Prince Sado, who was sealed alive in a rice chest by his own father King Yeongjo in 1762. \n\nThe fortress was designed by **Jeong Yak-yong (정약용, also known as Dasan)** — Joseon''s leading scholar-engineer of the Silhak (practical learning) school — who integrated traditional Korean defensive architecture with Chinese siege defense theory and emerging Western fortification science. \n\nJeong Yak-yong invented the **geojunggi (거중기)** — a pulley-and-block crane based on Western mechanical principles — for lifting heavy stones during construction; the first documented use of Western-style modern engineering in Korean construction. \n\nThe complete fortress wall is **5.74 km in circumference** enclosing 130 hectares with 41 strategic structures: 4 main gates (Janganmun north — the **largest existing royal gate in Korea**, larger than Seoul''s Sungnyemun; Paldalmun south; Hwaseomun west; Changnyongmun east), 4 angle towers, 4 command posts, 5 sentry platforms, 5 gun batteries, plus archery platforms, sluice gates, and beacon towers. \n\nToday''s guided walk covers the **most photogenic 1.2 km section between Janganmun (north main gate) and Hwaseomun (west gate, National Treasure No. 403)** — the highest density of preserved military structures, ~25-30 minutes of walking. Add the **Seojangdae (West Command Post)** atop Paldalsan Mountain for the fortress''s highest viewpoint and the king''s strategic command position. \n\n**Hwahongmun (north sluice gate)** with its 7 arches over Suwoncheon Stream is the most photographed structure of the fortress — especially in spring (cherry blossoms) and autumn (foliage). Tour group walks the wall on foot; an optional **Hwaseong Trolley** sightseeing tram (4,000 KRW adult, ~30 min, Yeonmudae→Paldalmun route) is available if schedule permits.","highlights":["**UNESCO World Heritage Site since 1997** — Korea''s only walled fortress city with original construction records","Built 1794-1796 in 2 years 9 months under King Jeongjo (22nd Joseon king)","Designed by Jeong Yak-yong using Korean + Chinese + Western fortification science","Hwaseong Seongyeok Uigwe construction record — UNESCO Memory of the World 2007","5.74 km circumference, 41 strategic military structures","Janganmun north gate — **largest existing royal gate in Korea**","1.2 km guided walk Janganmun → Hwaseomun (highest photo-density section)","Hwahongmun 7-arch sluice gate — most photographed structure","FREE for hanbok-wearers + last Wed of month + seniors 65+"],"timeUsed":["Coach drop-off near Janganmun (~5 min)","Brief group orientation at Janganmun (~5 min)","Walk Janganmun → Hwaseomun via Hwaseo Janggak (~25-30 min)","Photo time + reassembly at vehicle (~10 min)","Optional Hwaseong Yeolcha sightseeing trolley Yeonmudae↔Paldalmun (~30 min one-way; ₩4,000 adult)"],"whyOnRoute":"The route''s UNESCO anchor — Korea''s only remaining walled fortress city, built 1794-1796 under King Jeongjo. The Janganmun → Hwaseomun walk (~1.2 km) gives the highest density of preserved military structures + the iconic Hwahongmun 7-arch sluice gate in a 75-min stop. Picked over the full 5.74 km loop because the route covers the most photographed and historically rich section while preserving time for the day''s three other heritage stops. Hwaseong is also the **mandatory anchor of any Suwon day-trip** because it physically encloses the Haenggung palace and overlooks Nammun Market — meaning a single 4-5-hour Suwon block can deliver UNESCO World Heritage credentials, Joseon royal-residence interiority, and authentic traditional-market street-food without re-positioning the vehicle. The 1.2 km Janganmun → Hwaseomun wall section via Hwaseo Janggak is the highest-density preserved-military-architecture stretch in Korea (4 main gates + 5 secret gates + 4 sluices + Geojunggi-built ramparts coexist within 25-30 minutes walking time).","visitBasics":{"hours":"Wall path 24 hours (no gates); recommended 09:00-18:00 summer / 09:00-17:00 winter; evening hours May-Oct Wed-Sun 18:00-21:30","closed":"Open year-round (Hwaseong Trolley closed Mondays)","admission":"Adults 1,000 / Youth 700 / Children 500 KRW (FREE: children ≤6, seniors 65+, hanbok-wearers, last Wed of month). Hwaseong Trolley separate 4,000 KRW","walking":"Moderate — wall has steep sections at Seojangdae; stairs at gates; some sections wheelchair-difficult"},"convenience":{"restroom":"At Janganmun, Hwaseomun, Paldalmun, and Yeonmudae","parking":"Coach drop-off at Janganmun lot; designated coach parking at Yeonmudae"},"smartNotes":{"photo":"**Hwahongmun (north sluice gate)** with 7 arches over Suwoncheon Stream — the iconic shot, especially in spring (cherry blossoms) and autumn (foliage). **Janganmun (largest existing royal gate in Korea)** at golden hour. **Seojangdae (west command post)** sunset over Paldalsan Mountain.","facilities":"Visitor Information Center at Janganmun + Paldalmun + Hwaseong Haenggung Square. English-Korean signage throughout. Hwaseong audio guide rental at Janganmun.","tip":"Wear comfortable shoes — wall stones are uneven. Hanbok rental shops at Haenggung Square give FREE fortress + palace admission. **Avoid full 5.74 km loop unless allowing 2.5+ hours** — the Janganmun → Hwaseomun section gives the highest per-meter heritage density."},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 1","alt":"Suwon Hwaseong Fortress — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 2","alt":"Suwon Hwaseong Fortress — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 3","alt":"Suwon Hwaseong Fortress — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 4","alt":"Suwon Hwaseong Fortress — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 5","alt":"Suwon Hwaseong Fortress — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Suwon Hwaseong Fortress","caption":"Suwon Hwaseong Fortress — photo 6","alt":"Suwon Hwaseong Fortress — gallery image 6"}]},{"number":3,"time":"≈ 11:00","duration":"75 min","name":"Hwaseong Haenggung Palace","category":"Joseon Royal Detached Palace","description":"**Hwaseong Haenggung (화성행궁) — Korea''s largest existing haenggung (detached palace)** — was built 1789-1796 under King Jeongjo as part of the unified Hwaseong fortress city plan. \n\nA **haenggung** is a temporary/detached royal residence used by Joseon kings during travel, war refuge, or special ceremonies; Hwaseong Haenggung surpasses Onyang, Bukhansan, and Namhansan haenggung in scale. King Jeongjo built it primarily to stay overnight when visiting his executed father Crown Prince Sado''s tomb (Hyeollyungwon, now called Yungneung Royal Tomb, 4 km south) — a pilgrimage he made **13 times during his reign**. \n\nThe most famous of these journeys was the **1795 royal procession** with 6,000 attendants and 1,400 horses, celebrating the 60th birthday of Lady Hyegyeong (the king''s mother and Sado''s widow). \n\nThe 1795 procession is documented in the **Wonhaeng Eulmyo Jeongni Uigwe — UNESCO Memory of the World register since 2007**. The palace originally comprised **576 kan (rooms/structural bays)** functioning as a complete miniature royal residence with throne hall (Bongsudang), secondary hall (Naknamheon), residence quarters (Janganheon), kitchens, military offices, and guards'' quarters. \n\n**Largely destroyed during Japanese colonial period** (1910-1945) when the Japanese converted the palace site into Suwon Provincial Hospital and Police Station. \n\n**Restoration began 1996** following the original Hwaseong Seongyeok Uigwe construction record; first phase complete 2003 (Bongsudang, Naknamheon, Janganheon, Yuyeotaek), second phase complete 2009 (Wuhwagwan royal kitchen, Sinpung-nu entrance gate). Restoration continues today. \n\n**Critical historical note: Naknamheon (낙남헌) is the ONLY building that survived from the original 1796 construction** — Japanese converted it into Police Station offices but did not demolish it. It is therefore the only AUTHENTIC original wood-and-tile structure on the site; all other buildings are reconstructions. \n\n**Daily Royal Guard Changing Ceremony** at Sinpungnu Gate — **Tuesday-Sunday 11:00 AM** (weather permitting), ~15 min, FREE. Recreates the Joseon-era palace gate ceremony with guards in red, blue, and yellow uniforms with traditional drums and horns. \n\nThe tour times arrival for the 11:00 ceremony when day-of-week permits. Filmed for K-drama **''Jewel in the Palace'' (Daejanggeum, 2003)** — the iconic Joseon-era hit (peak ratings around 57% in Korea) — making this one of Korea''s most-filmed sageuk locations.","highlights":["**Korea''s largest existing haenggung (detached palace)** — originally 576 rooms","Built 1789-1796 alongside Hwaseong Fortress under King Jeongjo","King Jeongjo made 13 royal pilgrimages here to honor his executed father Crown Prince Sado","**Naknamheon = ONLY original 1796 structure remaining** (others are reconstructions)","**Royal Guard Changing Ceremony Tue-Sun 11:00 AM at Sinpungnu Gate (FREE, ~15 min)**","1795 Royal Procession documented in UNESCO Memory of the World","Filming location for K-drama ''Jewel in the Palace'' (2003, peak ~57% rating on MBC)","FREE for hanbok-wearers + seniors 65+ + children ≤6","**Naknamheon (낙남헌) is the ONLY building surviving from the original 1796 construction** — Japanese colonial-era authorities converted it into Police Station offices but did not demolish it; every other Haenggung structure visible today is a post-1996 reconstruction following the Hwaseong Seongyeok Uigwe (UNESCO Memory of the World since 2007)"],"timeUsed":["5 min walk from Hwaseong Fortress (Hwaseomun area)","Arrive in time for **11:00 Royal Guard Changing Ceremony** at Sinpungnu (~15 min)","Bongsudang Throne Hall + Naknamheon + Janganheon walk (~30 min)","Photo time + reassembly at vehicle (~15 min)","Optional Royal Guard Changing Ceremony at Sinpungnu Gate (Tue-Sun 11:00 AM, ~15 min, FREE — weather permitting)"],"whyOnRoute":"Pairs naturally with the fortress wall — the temporary royal residence is INSIDE the same UNESCO site, 5 minutes apart. Korea''s largest haenggung (576 rooms originally), with **Naknamheon the only authentic original structure** (the others are post-1996 reconstructions following the Hwaseong Uigwe). Time arrival for the Royal Guard Changing Ceremony (Tue-Sun 11:00 AM) which is FREE and ~15 min — one of the catalog''s strongest free cultural-experience hooks. Visiting Haenggung immediately after the fortress walls converts an abstract military-architecture lesson into lived royal-Joseon spatial experience — the same Bongsudang throne hall where King Jeongjo received officials in 1795 also hosted the lavish 60th-birthday banquet for his mother Lady Hyegyeong (depicted in the Banchado court-painting scrolls preserved in the Uigwe). A **Combined Fortress + Haenggung ticket** is sold at 3,500 KRW (vs 2,500 KRW separately) — a tangible value-added anchor for the Suwon stop. The Royal Guard Changing Ceremony at Sinpungnu Gate (Tue-Sun 11:00 AM, ~15 min, FREE) is timed to align with most Suwon-arrival schedules from a Seoul-departing day-trip.","visitBasics":{"hours":"09:00-18:00 (last entry 17:30); summer May-Oct evening hours 18:00-21:00","closed":"Open year-round","admission":"Adult 1,500 / Teen 1,000 / Child 700 KRW. Combined Fortress + Haenggung 3,500 KRW. FREE for hanbok-wearers, seniors 65+, children ≤6","walking":"Easy — palace grounds are mostly flat with some steps between courtyards"},"convenience":{"restroom":"At main entrance, near Bongsudang, and at Haenggung Square","parking":"Hwaseong Haenggung public parking; Haenggung Square paid lots"},"smartNotes":{"photo":"**Bongsudang Main Hall** — the iconic throne hall shot. **Naknamheon** — the only original 1796 structure (the most historically authentic photo). **Royal Guard Changing Ceremony at Sinpungnu Gate** (Tue-Sun 11:00 AM). Hanbok-wearers in front of Sinpungnu — Suwon''s most popular hanbok photo spot.","facilities":"Visitor Information Center, restrooms, gift shop. Haenggung Square cafes and hanbok rental (15,000-20,000 KRW for 4 hr). Suwon Tongdak (whole roast chicken) restaurants 5 min walk.","tip":"**Time arrival for 11:00 AM Royal Guard Changing Ceremony Tue-Sun (FREE)**. Hanbok rental gives FREE admission to BOTH Fortress and Haenggung. **Naknamheon is THE single most historically important spot** — the only structure not rebuilt, surviving Japanese colonial demolition. Skip Mondays — Royal Guard Changing Ceremony performed Tue-Sun only."},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 1","alt":"Hwaseong Haenggung Palace — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 2","alt":"Hwaseong Haenggung Palace — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 3","alt":"Hwaseong Haenggung Palace — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 4","alt":"Hwaseong Haenggung Palace — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 5","alt":"Hwaseong Haenggung Palace — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Hwaseong Haenggung Palace","caption":"Hwaseong Haenggung Palace — photo 6","alt":"Hwaseong Haenggung Palace — gallery image 6"}]},{"number":4,"time":"≈ 12:30","duration":"120 min","name":"Korean Folk Village (Yongin)","category":"Folk Heritage Village","description":"**Korean Folk Village (한국민속촌, Yongin) — Korea''s first and largest open-air museum of traditional folk culture**, occupying ~991,735 m² (245 acres / 300,000 pyeong) of natural valley terrain in Yongin city, ~30 minutes drive from Suwon. \n\n**Over 260 traditional houses and structures reproduced from the late Joseon Dynasty** represent every region of Korea (Seoul, Gyeonggi, Hwanghae, Pyongan, Hamgyong, Gangwon, Chungcheong, Jeolla, Gyeongsang, Jeju) and every social class (commoner farmhouses through yangban scholar-class residences) — a complete sociological tapestry of pre-modern Korea. \n\n**9 traditional craft workshops** (forge, paper-making, pottery, weaving, etc.) house artisans demonstrating live craft. The village is famous for **daily traditional performances** running on a published schedule: **Nong-ak (farmers'' percussion music), Jultagi (tightrope walking — UNESCO Intangible Cultural Heritage of Korea, performed with comedic narration), horseback martial arts (mounted acrobatics with sword swings while galloping), and traditional Joseon wedding ceremony reenactments**. \n\nPerformance times typically 10:30/14:00/15:30 — confirm at the entrance. **Hands-on activities**: ferry rides on the village pond, horseback riding, natural fabric dyeing, hanbok rental (free 30-min trial inside the gate), archery range, Confucian School visit. \n\nA modest amusement-park section with kid-friendly rides is included with combo tickets. **Frequently used as a Joseon-era filming set for K-drama sageuk (historical) productions** — including the iconic **Jewel in the Palace (Daejanggeum, 2003)**, **Sungkyunkwan Scandal (2010)**, **Mr. Sunshine (2018)**, and many others. \n\nThe ''Welcome to Joseon'' annual festival is the village''s signature spring event; **autumn (last two weeks of October)** is photographically optimal with golden ginkgo and red maple foliage at the yangban two-story house. \n\nThe route''s largest single time block (~2 hours of walking) — the most viscerally late-Joseon experience on the day.","highlights":["**Korea''s first + largest open-air museum** of traditional folk culture (991,735 m² / 245 acres)","260+ traditional houses representing every Korean region + social class","9 active traditional craft workshops (forge, paper, pottery, weaving)","**UNESCO Intangible Cultural Heritage Jultagi (tightrope walking) demonstrations**","Nong-ak farmers'' percussion + horseback martial arts + Joseon wedding reenactments","Filming location for Jewel in the Palace (peak ~57% rating on MBC), Sungkyunkwan Scandal, Mr. Sunshine","**Last 2 weeks of October = photographic peak** (golden ginkgo + red maples)","Modest amusement-park section included with combo tickets (family-friendly)","**Jultagi (줄타기) tightrope-walking** — performed daily — is **UNESCO Intangible Cultural Heritage of Humanity since 2011**: the only Korean tightrope tradition where the walker engages in comedic dialogue with a ground-level musician/MC throughout the performance"],"timeUsed":["30-min drive from Hwaseong Haenggung to Yongin (~30 min)","Group ticketing + entrance orientation (~5 min)","Self-guided village walk + craft workshops (~80 min)","Performance attendance if timed (Nong-ak / Jultagi / wedding reenactment, ~20-30 min)","Reassembly at vehicle (~15 min)"],"whyOnRoute":"The day''s biggest heritage block (~2 hours of walking) and the most viscerally late-Joseon stop on the route. 260+ houses representing every region and class, working artisans, equestrian shows, traditional wedding ceremonies, and UNESCO Intangible Heritage Jultagi tightrope walking — all of which dramatize the curated abstraction of Hwaseong''s military architecture into visceral living-Joseon experience. **30-min drive each way is offset by 2-hour anchor**. Korean Folk Village is the **definitive sageuk K-drama production set in Greater Seoul** — filming credits include ''Jewel in the Palace / Daejanggeum'' (2003-04, peak ratings around 57% in Korea across 54 episodes), ''Sungkyunkwan Scandal'' (2010), ''Moonlight Drawn by Clouds'' (2016), and many others. For Hallyu-driven travelers, this delivers more authenticity-per-hour than visiting individual filming locations scattered across multiple Korean provinces. A free shuttle bus from Suwon Station Visitor Center (~30 min) or direct Bus 5001-1 from Gangnam Station Exit 5 makes this the most operationally seamless K-drama anchor pair with Hwaseong on a single Seoul-departing day.","visitBasics":{"hours":"Mon-Thu 10:00-18:00; Fri-Sun and holidays 10:00-22:00 (winter shorter — Nov-Feb 09:30-17:30)","closed":"Open year-round","admission":"Adult 37,000 / Teen 32,000 / Child 26,000 KRW (Visit Korea official; combo includes amusement-rides section). Folk Village only ~22,000 KRW adult","walking":"Moderate — large grounds (~5-7 km if exploring fully); paths are flat to gently sloping dirt and gravel"},"convenience":{"restroom":"Multiple restrooms throughout, signposted","parking":"Dedicated lot — passenger cars 2,000 KRW, SUVs/trucks 3,000 KRW; tour-coach lot accommodates groups"},"smartNotes":{"photo":"**Last two weeks of October peak for golden ginkgo + maples** in the nobleman''s compound. The yangban two-story house and the marketplace street are the most visually rich. Hanbok rental + traditional arena makes for the most popular family shots. Jultagi tightrope-walking performance is high-action photo opportunity.","facilities":"Traditional street-market stalls sell local snacks (Imsil cheese pizza, railroad hotdogs, Winibini candy). Multiple sit-down restaurants serving Korean village-style menus. Hanbok rental free 30-min trial inside the gate.","tip":"**Check the daily English performance timetable at the gate** — Jultagi (UNESCO Intangible Heritage tightrope walking) and Nong-ak farmers'' percussion + traditional Joseon wedding reenactment are the can''t-miss shows. **Best visit October 20-November 5** for autumn foliage peak. Pair with Hwaseong Fortress for a coherent Joseon-themed day. Allow 2 hours minimum; some visitors easily spend 3-4 hours."},"_poi_meta":{"poi_key":"korean_folk_village_yongin","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","HereKoreaTravel","Wikipedia","Korea Tourism Organization (english.visitkorea.or.kr — Korean Folk Village official listing)","Korean Folk Village Yongin (koreanfolk.co.kr — operating hours + festival schedule + admission)","UNESCO Intangible Cultural Heritage of Humanity (Jultagi tightrope walking — 2011 inscription)","Wikipedia (Korean Folk Village — 245 acres / 260 traditional houses / 1974 founding)","Visit Korea KTO Sageuk K-Drama Filming Locations Guide (Daejanggeum/Jewel-in-the-Palace + Sungkyunkwan Scandal)"],"note":"Reference fix: Phase 1 used poi_key ''korean_folk_village''; KB canonical key is ''korean_folk_village_yongin''."},"image":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","images":["/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp"],"imageCredits":[{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","source":"atoc-korea"},{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"Korean Folk Village (Yongin)","caption":"Korean Folk Village (Yongin) — photo 1","alt":"Korean Folk Village (Yongin) — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"Korean Folk Village (Yongin)","caption":"Korean Folk Village (Yongin) — photo 2","alt":"Korean Folk Village (Yongin) — gallery image 2"}]},{"number":5,"time":"≈ 15:30","duration":"75 min","name":"Starfield Library Suwon","category":"Modern Cultural Landmark","description":"**Starfield Library Suwon (별마당 도서관 수원)** — inside **Starfield Suwon, Shinsegae''s flagship ''second-generation'' Starfield mall opened January 26, 2024** as the fifth Starfield mall and the largest by gross floor area outside Hanam (~334,000 m²). Designed in collaboration with **BCHO Partners (Cho Byoung-soo)** — the Korean firm also responsible for the original Starfield Library at COEX (2017) — Suwon''s library represents the second-generation iteration with **bookshelves rising up to 22 meters tall**, among the tallest cylindrical bookshelf structures in any Korean public space. \n\nThe library spans **4 floors** (4F-7F atrium space) housing **a large on-site collection of books and magazines** including Korean and international publications, periodicals, art books, and a dedicated children''s literature section on 4F. \n\n**FREE and open to the public** — no library card, no admission fee, accessible during all mall hours (10:00-22:00 daily). Books cannot be borrowed (read-on-site only). Distinctive features: **Vinyl Record Listening Lounge** with curated Korean indie + international jazz/classic rock vinyl; **monthly rotating art exhibition** in the atrium space partnering with Korean contemporary artists; and **seasonal cherry blossom installation in the central atrium (March-April)** with thousands of pink LED petals — one of Suwon''s most photographed spring spots. \n\nAdjacent mall amenities include: **Eatopia food hall (B1F)** with 30+ restaurants from quick-service Korean (5,000-10,000 KRW) to premium dining (40,000+ KRW); **Aquafield Suwon water park + Korean spa (B1-2F)** separate paid admission ~25,000-35,000 KRW; **Toy Kingdom (4F, Korea''s largest toy store)**; and a CGV/MEGABOX dual cinema setup. \n\n**Free Starfield shuttle bus** runs from Suwon Station Exit 4 every 10-15 min (~10 min ride) — the easiest access from public transit. The ''modern Korea'' counterweight after three Joseon-heritage stops, providing covered indoor finish that buffers any late-afternoon weather risk.","highlights":["**Shinsegae''s flagship 2nd-generation Starfield mall — opened January 26, 2024**","Designed by BCHO Partners (also designers of original COEX Starfield Library 2017)","**4-floor library with 22-meter bookshelves** — among Korea''s tallest cylindrical bookshelves","Large open reading collection accessible FREE","Vinyl Record Listening Lounge with curated collection","Cherry blossom LED-petal installation in atrium (March-April)","Eatopia food hall (30+ restaurants), Aquafield water park, Toy Kingdom, CGV/MEGABOX cinema","Free Starfield shuttle from Suwon Station Exit 4 (~10 min)","Mall hours 10:00-22:00 daily"],"timeUsed":["15-min drive from Yongin / Korean Folk Village","Mall + library walking tour (~45-50 min)","Café break at library or food hall (~15 min)","Reassembly at vehicle","Optional Vinyl LP cafe lounge (5F, ~₩18,500 incl. drink + headphones + LP record-player access; ~30-45 min)"],"whyOnRoute":"The ''modern Korea'' counterweight after three heritage stops (fortress + palace + folk village). Shinsegae''s flagship 2nd-generation Starfield mall opened January 26, 2024; the four-floor library with 22 m bookshelves and vinyl-listening section is the architectural highlight. **All-indoor stop** — buffers any late-afternoon weather risk and provides genuine multi-generational appeal (kids → Toy Kingdom; teens → vinyl + bookshelves; adults → café + shopping). Starfield Library is the **single most Instagram-photographed indoor space in Greater Seoul outside of central Seoul** (per Korean travel-media surveys 2024-25) — the 22m bookshelves (vs Seoul COEX''s 13m) span 4 mall floors (4F-7F atrium void), and the rooftop-level **''The Planets'' installation by Canadian novelist-designer Douglas Coupland** is exclusive to the Suwon location. **FREE admission, no membership, photos permitted** — making this a no-friction closing photo stop after the more-paid Hwaseong/Haenggung/Folk-Village earlier in the day. From Suwon Station: Subway Line 1 to Hwaseo Station Exit 1/4 (~3 min on subway, 8-min walk), or free Starfield shuttle bus (every 10-15 min from Suwon Station Exit 4).","visitBasics":{"hours":"Mall 10:00-22:00; library accessible during all mall hours","closed":"1-2 monthly closure days (typically Mondays — verify online before visit)","admission":"**Library FREE** (mall-wide free entry; pay-as-you-go for shopping; Aquafield water park separate ~25,000-35,000 KRW)","walking":"Easy — escalators and elevators between all floors; wheelchair/stroller accessible throughout"},"convenience":{"restroom":"Multiple restrooms on every floor; family-friendly with diaper-changing stations","parking":"Underground parking ~5,000 spaces; first 3 hours FREE with mall purchase 30,000 KRW+; coach lot for groups"},"smartNotes":{"photo":"**Library central atrium with 22-meter bookshelves** — the iconic shot, best from 4F gallery looking down. **Vinyl Record Lounge** for retro aesthetic. **Cherry blossom installation in atrium (March-April)** — viral seasonal photo. Christmas tree (December). Children''s section on 4F for family photos.","facilities":"Eatopia food hall B1F (30+ restaurants 5,000-40,000 KRW), Toy Kingdom 4F, Aquafield water park B1-2F, T-Joy + CGV + MEGABOX cinema, free WiFi, multilingual customer service, tax-refund counters at major stores.","tip":"**Library is FREE** — exceptional value attraction. **Free Starfield shuttle from Suwon Station Exit 4** is the easiest access (every 10-15 min). **22-meter bookshelves = Korea''s tallest library bookshelves** (mention to guests for impact). **Cherry blossom installation March-April** is the seasonal must-see. Avoid Saturday afternoons (peak crowd density). 1-2 monthly closure days — verify online before visit."},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-05-21","sources":["Starfield official","VisitKorea","Shinsegae press release","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield Library Suwon","caption":"Starfield Library Suwon — photo 1","alt":"Starfield Library Suwon — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield Library Suwon","caption":"Starfield Library Suwon — photo 2","alt":"Starfield Library Suwon — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield Library Suwon","caption":"Starfield Library Suwon — photo 3","alt":"Starfield Library Suwon — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield Library Suwon","caption":"Starfield Library Suwon — photo 4","alt":"Starfield Library Suwon — gallery image 4"}]},{"number":6,"time":"≈ 17:00","duration":"60 min","name":"Return to Seoul","category":"Return","description":"Coach back to central Seoul, with **drop-off at the same morning meeting points** (Hongik University Station Exit 8 or Myeongdong Station Exit 2/4). Arrival typically **18:00-18:30 depending on traffic** — late afternoon traffic on the Gyeongbu Expressway can add 15-20 min cushion vs. the morning drive.","highlights":["Coach return via Gyeongbu Expressway","Drop-off at Hongik University or Myeongdong (same as morning pickup)","Typical arrival 18:00-18:30"],"timeUsed":["Coach drive from Suwon to Seoul (~60 min)","Drop-off at designated point"],"whyOnRoute":"Return logistics — drop-off chosen for guest convenience and timing certainty. Central Seoul drop-off in the early evening preserves time for independent dinner planning.","visitBasics":{},"convenience":{},"smartNotes":{"tip":"Final arrival depends on Friday-evening / weekend traffic; on heavy days the drop-off may add 15-20 min."},"_poi_meta":{"poi_key":"OPS_return","verified":false,"match":"operational_implicit","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational stop (return)"},"_role":"dropoff"}],"routeFlowStops":[{"name":"Seoul","type":"origin","theme":"Departure"},{"name":"Suwon Hwaseong Fortress","type":"primary","theme":"UNESCO Fortress"},{"name":"Hwaseong Haenggung Palace","type":"primary","theme":"Heritage Palace"},{"name":"Korean Folk Village (Yongin)","type":"primary","theme":"Heritage Village"},{"name":"Starfield Library Suwon","type":"secondary","theme":"Modern Korea"},{"name":"Seoul","type":"return","theme":"Return"}],"routePhases":[{"phase":"Outbound","duration":"≈ 1 hour","description":"Seoul → Suwon city via Gyeongbu Expressway."},{"phase":"Heritage half","duration":"≈ 3 hours","description":"Suwon Hwaseong walls and Haenggung palace, all walking distance from each other."},{"phase":"Folk village","duration":"≈ 2.5 hours","description":"Drive 30 minutes to Yongin''s Korean Folk Village, then explore the open-air park."},{"phase":"Modern coda","duration":"≈ 1.5 hours","description":"Drive back to Suwon for Starfield Library and mall food hall."},{"phase":"Return","duration":"≈ 1 hour","description":"Suwon → Seoul."}],"routeShapeIntro":{"title":"How this day flows","subtitle":"A compact triangle south of Seoul — Suwon''s UNESCO fortress city, Yongin''s open-air Joseon village, and Suwon''s flagship modern mall — that adds up to a four-stop survey of Korean public space across 250 years. Walls in the morning, thatched roofs at midday, glass and books in the late afternoon."},"whyTourWorks":{"bestFor":["First-time Korea visitors who want one UNESCO World Heritage site (Hwaseong) plus one open-air heritage village in a single day","K-drama and history-leaning travelers who''ll recognize the Folk Village''s filming locations from major historical series","Photography travelers — the Starfield Library''s four-floor atrium with 22 m shelves is one of Korea''s most photographed contemporary spaces","Couples and adult families who can handle ≈4-5 km of walking across the day at a guided pace","Travelers who prefer Gyeonggi Province''s heritage range over staying inside Seoul''s central palaces"],"lessIdealFor":["Travelers with limited mobility — the fortress wall has steep sections, stairs at gates, and uneven paving","Stroller-heavy groups (Folk Village paths are mostly flat but the wall is not stroller-friendly)","Anyone needing a tight same-day flight buffer (Seoul return ≈ 18:00 with traffic risk)","Visitors who want to see Seoul''s central palaces (Gyeongbokgung, Changdeokgung) — this trip stays in Gyeonggi","Mall-shopping-focused travelers — Starfield Suwon is here for the library, not retail (food hall + browsing only, ≈60-90 min budget)"],"routeLogicSections":[{"title":"Why this route is built this way","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"UNESCO + folk village + library, in one day","detail":"These are three of Gyeonggi''s most-visited day-trip targets, and they''re each awkward to reach by bus and subway from Seoul. The tour combines them into a single coach loop with admissions included, saving you the planning and the transfers."},{"label":"More substantive than the standard ''fortress + library'' run","detail":"Many Suwon tours skip either Haenggung Palace or the Folk Village. This one keeps both, which is what makes the Joseon-era story actually land — you see the wall, the king''s residence inside it, and the village life it was built to govern."},{"label":"Free admission, paid context","detail":"Starfield Library is free to enter on your own — but it''s much more rewarding with a guide who can explain why a mall built it (Shinsegae''s MZ-generation strategy), how it differs from the COEX original, and where the best photo angles are without disturbing readers."},{"label":"Year-round route","detail":"Unlike Nami Island or Seoraksan trips that swing strongly with seasons, this itinerary works in any weather. The fortress, the palace, and the folk village all run in winter; the library is indoors. Good fallback when foliage or cherry-blossom timing isn''t on your side."}]},{"title":"How the walking load actually feels","icon":"footprints","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","items":[{"label":"Fortress wall: the day''s hardest section","detail":"The 1 km walked between Janganmun and Hwaseomun has steep sections and stairs at gates. Comfortable shoes essential. Wheelchair-difficult on this stretch."},{"label":"Folk Village: ≈2 hours, mostly flat","detail":"The grounds are large but paths are flat to gently sloping. Plan ≈2 hours of walking; sit-down performance breaks help. Stroller-friendly."},{"label":"Haenggung & Starfield: easy","detail":"Palace grounds are flat with some courtyard steps. Starfield Library is escalator/elevator accessible across all four floors."}]},{"title":"When weather and seasons shift","icon":"cloud-sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Cherry blossoms early April","detail":"The fortress walls are lined with cherry trees — early April is the peak photo window. Hanbok rental at the palace makes the day''s best photos."},{"label":"Summer heat July-August","detail":"The fortress wall has minimal shade. The day shifts toward Folk Village shaded paths and indoor Starfield time. Hydration essential."},{"label":"Winter cold December-February","detail":"The wall walk is shorter on cold days; Folk Village indoor performance schedules thin out. Starfield is the natural longer stop."}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"What''s included","preview":"Round-trip coach transport from Seoul, English-speaking tour guide, Suwon Hwaseong…","content":["Round-trip coach transport from Seoul, English-speaking tour guide, Suwon Hwaseong Fortress admission, Hwaseong Haenggung Palace admission, Korean Folk Village admission.","Not included: meals, drinks, optional folk-village experiences (hanbok rental, archery), tips.","Starfield Library entry is free."]},{"id":"pickup","title":"Pickup & drop-off","preview":"Hongik University Station (Exit 8) at ≈08:00 or Myeongdong Station (Exit 2 or 4) at ≈08:30.","content":["Hongik University Station (Exit 8) at ≈08:00 or Myeongdong Station (Exit 2 or 4) at ≈08:30.","Arrive 10 minutes early.","There is no hotel pickup; meeting points only.","Latecomers cannot be accommodated."]},{"id":"walking","title":"Walking & terrain","preview":"Moderate.","content":["Moderate.","The fortress wall walk involves uphill stone steps and uneven surfaces — about 1 km of the 5.7 km loop is typically covered.","The Folk Village is a large open-air site (≈245 acres) but flat.","Starfield Library involves stairs and escalators between floors.","Comfortable walking shoes essential."]},{"id":"what","title":"What to wear & bring","preview":"Comfortable closed-toe walking shoes, sunhat in summer, layered clothing in…","content":["Comfortable closed-toe walking shoes, sunhat in summer, layered clothing in spring/autumn, warm coat in winter (the fortress walls are exposed to wind).","Camera, water, light snacks.","Cash for lunch and any optional folk-village add-ons."]},{"id":"cancellation","title":"Cancellation","preview":"Free cancellation up to 24 hours before the tour starts.","content":["Free cancellation up to 24 hours before the tour starts.","Same-day cancellations and no-shows are non-refundable."]},{"id":"children","title":"Children & accessibility","preview":"Children are welcome — the folk village in particular is family-friendly, with horse…","content":["Children are welcome — the folk village in particular is family-friendly, with horse shows and traditional games.","Strollers can navigate Haenggung and the folk village''s main paths.","The fortress wall walk has stairs and is not stroller-friendly.","Limited accessibility for wheelchair users on fortress sections."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"See seasonal notes"},"tomorrow":{"temp":"—","label":"See seasonal notes"},"_seasonalSummary":"Suwon and Yongin track Seoul''s weather closely (about 30 km south). Plan for hot, humid summers and cold, dry winters; spring and autumn are the most comfortable.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"5–22°C","notes":"Cherry blossoms along the fortress wall in early–mid April."},{"season":"Summer (Jun–Aug)","range":"22–32°C","notes":"Hot and humid; bring sun protection and water."},{"season":"Autumn (Sep–Nov)","range":"8–22°C","notes":"Best season — clear skies, mild temperatures."},{"season":"Winter (Dec–Feb)","range":"-5 to 6°C","notes":"Cold winds on the fortress wall; library is indoors and warm."}]},"seasonalVariations":[{"season":"Spring","description":"Cherry blossoms along the Hwaseong wall and at the folk village; major Suwon Hwaseong Cultural Festival in early autumn."},{"season":"Summer","description":"Folk-village water festival; evening lighting at Haenggung on selected nights."},{"season":"Autumn","description":"Maple foliage along the fortress wall, peak Korean Folk Village season for traditional weddings and harvest demos."},{"season":"Winter","description":"Snow on the fortress wall is one of Korea''s classic photographs; folk village hosts winter customs (kimjang, ondol fires)."}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local operator","description":"Authorized Korean tour operator with full insurance","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Route specialists","description":"Hand-tuned itinerary, not a generic loop","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Curated group size","description":"Right-sized for the route","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"12 hours before","title":"12-Hour Reminder","detail":"Weather update and any route adjustments"},{"timing":"Evening before","title":"Final Pickup Info","detail":"Exact pickup time and driver contact"},{"timing":"Morning of tour","title":"Day-of Route Notes","detail":"Morning briefing based on live conditions"},{"timing":"During tour","title":"Stop-by-Stop Tips","detail":"Real-time guidance at each location"},{"timing":"After tour","title":"Post-tour Support","detail":"Follow-up and recommendations"}],"staticQuestions":[{"id":"q1","question":"Are admissions included?","answer":"Yes — Suwon Hwaseong Fortress, Hwaseong Haenggung Palace, and Korean Folk Village admission are all included. Starfield Library is free for everyone. Hanbok rental, archery, or other optional folk-village add-ons are at your own cost."},{"id":"q2","question":"Is lunch included?","answer":"No. Lunch is typically eaten during free time at Starfield Suwon''s food hall (large variety, ₩10,000–₩20,000) or at a small Suwon eatery near the fortress (Suwon-style galbi or chicken)."},{"id":"q3","question":"How much of the fortress wall do we walk?","answer":"About 1 km of the 5.7 km loop, typically the section between Janganmun and Hwaseomun, including some bastions and a beacon mound. The full loop takes 3+ hours and isn''t covered in this itinerary."},{"id":"q4","question":"Is Starfield Library worth a full hour?","answer":"Yes for first-time visitors — it''s an architectural draw on its own. Free time is also for late lunch, coffee, or browsing the Starfield Suwon mall (Korea''s flagship 2nd-generation Starfield, opened January 2024)."},{"id":"q5","question":"Can I rent a hanbok at the Folk Village?","answer":"Yes, hanbok rental is available on-site for an extra fee (typically ₩10,000–₩20,000 for 1–2 hours). Wearing hanbok also gets you discounts on traditional-experience activities. The guide can point you to the rental booth."},{"id":"q6","question":"Is there a difference from the Suwon + Waujeongsa tour?","answer":"Yes. This tour adds the Korean Folk Village (a major heritage site) and uses Starfield Library as the modern stop. The Waujeongsa version drops the Folk Village and replaces it with the giant-Buddha temple in Yongin. Choose this one if heritage depth matters more; the Waujeongsa version if Buddhist sculpture matters more."},{"id":"first-time","question":"Is this a good choice for first-time visitors to Suwon & Yongin?","answer":"Yes — strong first-time pick for travelers wanting one UNESCO site (Hwaseong Fortress), one heritage village (Korean Folk Village), one Joseon palace (Haenggung), and one contemporary photo space (Starfield Library) in a single day. The format covers four contrasting sides of Korean culture without retreading central Seoul palaces. Geographically the route stays in the Suwon-Yongin corridor."},{"id":"walking","question":"Is the walking difficult?","answer":"Active walking day, ≈4-5 km total. Hwaseong wall is the hardest section: 1 km walked between Janganmun and Hwaseomun, with steep gradients, stairs at gates, and uneven historic surfaces. Korean Folk Village adds ≈2 hours of walking on flat-to-gently-sloping paths (270+ houses spread out). Haenggung Palace and Starfield Library are easy indoor/courtyard surfaces. Comfortable shoes essential."},{"id":"family","question":"Is this tour suitable for families?","answer":"Yes for families whose kids can handle a 10-hour day with several walking-heavy stops. The Folk Village is the family highlight — 270+ traditional houses, equestrian shows, K-drama filming locations, traditional weddings on weekends. Hanbok rental at Haenggung Palace is a fun photo moment (and gets free fortress admission for hanbok wearers). Strollers difficult on the wall, fine at Starfield and Folk Village."},{"id":"seniors","question":"Can older adults join comfortably?","answer":"Recommended only for active seniors comfortable with stairs and uneven ground. The fortress wall is the hardest section — steep gradients and stairs make some stretches wheelchair-difficult. Seniors can walk easier wall segments and skip command posts. Folk Village paths are flat to gently sloping, walkable for most. Haenggung is mostly flat. Starfield is fully escalator/elevator-accessible."},{"id":"children","question":"What''s the recommended minimum age?","answer":"Best fit is around age 10 and up — the day involves significant walking on the fortress wall (uneven surfaces), an active Folk Village exploration, and a long day overall. Younger children can join with carriers but the 1 km wall walk plus the 2-hour Folk Village can tire 6-9 year-olds. Equestrian shows and traditional performances at the Folk Village are crowd-pleasers for older kids."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"59","currency":"USD","per":"person","salePriceUsd":59,"originalPriceUsd":66,"discountPercent":11}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:00","name":"Hongik Univ. Station (Exit 8)","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"time":"08:30","name":"Myeongdong Station (Exit 2 or 4)","type":"station","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"Hongik Univ. Station (Exit 8)","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"name":"Myeongdong Station (Exit 4)","type":"station","lat":37.56099,"lng":126.98619}],"notes":["Arrive 10 minutes early. Latecomers cannot be accommodated and are non-refundable."]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-folk-village-starfield-library","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"coach","duration_hours":10,"region_tags":["gyeonggi_suwon","gyeonggi_goyang"],"theme_tags":["unesco","fortress","folk_village","modern_landmark","mixed_culture"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","korean_folk_village","starfield_library_suwon"],"pace_level":0.6,"walking_level":0.8,"scenic_level":0.8,"photo_level":1,"culture_level":1,"relax_level":0.6,"first_time_fit":0.95,"family_fit":0.85,"senior_fit":0.7,"couple_fit":0.85,"solo_traveler_fit":0.85,"active_traveler_fit":0.5,"adult_family_fit":1,"family_with_teens_fit":1,"young_kids_fit":0.7,"senior_active_fit":0.6,"senior_general_fit":0.7,"mobility_friendly_fit":0.55,"stroller_fit":0.5,"one_day_fit":1,"same_day_flight_fit":0.3,"rain_fit":0.65,"value_for_money_fit":0.95,"iconic_landmark_fit":1,"cafe_fit":0.7,"food_fit":0.6,"nature_fit":0.5,"beach_fit":0,"nightlife_fit":0.05,"shopping_fit":0.7,"no_shopping_fit":0.5,"local_culture_fit":1,"storytelling_fit":1,"unesco_fit":1,"intangible_heritage_fit":1,"indoor_ratio":0.4,"weather_sensitivity":0.4,"comfort_level":0.6,"budget_fit":0.7,"premium_fit":0.4,"small_group_fit":1,"private_fit":0.05,"bus_fit":1,"price_band":"mid","pickup_base":"seoul_central","return_time_band":"18:00-19:30","duration_band":"10h","min_recommended_age":10,"hard_constraints":{"avoidIf":["tight_same_day_departure"],"notIdealFor":["very_low_mobility","stroller_heavy_groups"]},"walking_notes":["Active walking day with some stairs and uneven terrain.","Average fitness expected.","