  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","locale":"ja","product_id":"seoul-suwon-hwaseong-folk-village-starfield-library","seo":{"pageTitle":"水原華城・民俗村＆スターフィールドライブラリー | AtoC Korea","metaDescription":"ソウル発10時間少人数デイツアー：ユネスコ登録・水原華城、華城行宮、韓国民俗村（龍仁）、スターフィールド水原ライブラリー。","primaryKeywords":["ソウル発水原華城ツアー","韓国民俗村日帰り旅行","スターフィールドライブラリー水原ツアー","ユネスコ韓国日帰りツアー"],"ogImage":"https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"ソウル発 水原華城・韓国民俗村＆スターフィールドライブラリー日帰りツアー | AtoC Korea"},"catalog_card":{"thumbnail":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"水原：華城・民俗村＆スターフィールド","priceLabel":"","shortCardDescription":"ソウルから京畿道へ向かう少人数文化日帰り旅行。韓国の歴史遺産と現代の暮らしの対照的な4つの側面をめぐります：ユネスコ世界遺産に登録された水原華城（18世紀の城壁と城門）、朝鮮時代の再現イベントが催される復元された華城行宮、龍仁にある没入感あふれる野外型韓国民俗村、そして圧倒的な存在感を放つ4フロアのスターフィールドライブラリー水原。交通費と入場料込みの10時間ツアー。","tags":["small_group","文化","ユネスコ","歴史遺産","ライブラリー","folk_village","day_trip"],"rating":0,"reviewCount":0,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","subtitle":"ソウルから京畿道へ向かう少人数文化日帰り旅行。韓国の歴史遺産と現代の暮らしの対照的な4つの側面をめぐります：ユネスコ登録の…","region":"京畿道（ソウル南部）","duration":"10時間","stopsCount":6,"badges":["少人数グループ","文化","UNESCO","歴史遺産","ライブラリー","民俗村","日帰り旅行"],"heroImage":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp"},"headlineLine1":"水原歴史遺産の一日","headlineLine2":"華城・民俗村＆スターフィールド","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null},"hero":{"imageUrl":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","imagePosition":"center 35%","tagline":"韓国唯一の城郭要塞、民俗村、そしてインスタグラムで話題のライブラリー","pills":["少人数グループ","文化"],"meta":{"duration":"10時間","region":"京畿道（ソウル南部）","stops":"6か所","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"概要"},{"id":"itinerary","label":"旅程"},{"id":"details","label":"詳細"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"レビュー"}],"glanceItems":[{"icon":"camera","label":"撮影価値","value":"優秀","level":5},{"icon":"mountain","label":"景観","value":"良い","level":4},{"icon":"footprints","label":"徒歩","value":"高い","level":4},{"icon":"cloud-rain","label":"雨天時の安全性","value":"良い","level":4},{"icon":"users","label":"ファミリー向け","value":"良い","level":4},{"icon":"gauge","label":"バランス","value":"バランス良好","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","alt":"水原華城 — ギャラリー画像1","caption":"水原華城 — 写真1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"韓国民俗村（龍仁）","alt":"韓国民俗村（龍仁） — gallery image 1","caption":"韓国民俗村（龍仁） — photo 1"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"スターフィールド図書館 水原","alt":"スターフィールド図書館 水原 — gallery image 1","caption":"スターフィールド図書館 水原 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","alt":"水原華城 — ギャラリー画像2","caption":"水原華城 — 写真2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","alt":"水原華城 — ギャラリー画像3","caption":"水原華城 — 写真3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","alt":"水原華城 — ギャラリー画像4","caption":"水原華城 — 写真4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","alt":"水原華城 — ギャラリー画像5","caption":"水原華城 — 写真5"},{"id":8,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"韓国民俗村（龍仁）","alt":"韓国民俗村（龍仁） — gallery image 2","caption":"韓国民俗村（龍仁） — photo 2"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"スターフィールド図書館 水原","alt":"スターフィールド図書館 水原 — gallery image 2","caption":"スターフィールド図書館 水原 — photo 2"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"スターフィールド図書館 水原","alt":"スターフィールド図書館 水原 — gallery image 3","caption":"スターフィールド図書館 水原 — photo 3"},{"id":11,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"スターフィールド図書館 水原","alt":"スターフィールド図書館 水原 — gallery image 4","caption":"スターフィールド図書館 水原 — photo 4"}],"itineraryStops":[{"number":1,"time":"≈ 08:00","duration":"10分","name":"ソウル出発","category":"ピックアップ＆出発","description":"ソウル中心部の2か所の集合場所からピックアップ：**弘益大学駅8番出口**（弘大エリア、ソウル地下鉄2号線／空港鉄道）または**明洞駅2番または4番出口**（ソウル地下鉄4号線）。予約時に正確なピックアップ時間と場所をご確認ください。スケジュールは、午前遅めの韓国ツアー団体ラッシュ前に華城に到着できるよう、早めの出発を基本としています。\n\n京釜高速道路を経由して**水原まで約1時間のコーチ移動**。水原は朝鮮王朝の正祖王が、処刑された父・思悼世子の陵を称え守るために華城（1794〜1796年）を築いた歴史的な城郭都市です。平日（月〜金）の朝は渋滞が少なく、週末は15〜20分の余裕をみてください。コーチには冷房が完備され、ほとんどの座席にUSB充電ポートが設置されています。","highlights":["弘益大学（2号線）または明洞（4号線）から午前8時頃ピックアップ","京釜高速道路経由、水原まで1時間のコーチ南下","冷房完備＋USB充電付きコーチ","団体ツアーラッシュ前に華城へ早着できるよう設計"],"timeUsed":["ソウルの指定集合場所で合流（乗車約5分）","水原までコーチで約1時間（渋滞のない場合、約60分）"],"whyOnRoute":"ソウルを午前9時に出発することで、正午前の混雑を避けて華城に到着でき、韓国民俗村の午後の公演スケジュール（韓服婚礼式の再現、馬上武芸、農楽）にも合わせることができます。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"予約時に正確なピックアップ時間と集合場所をご確認ください。ソウルの朝のラッシュアワー（7:00〜9:00）は時間厳守が不可欠です。水分、日焼け止め、歩きやすい靴をご持参ください。"},"_poi_meta":{"poi_key":"OPS_seoul_pickup_default","verified":false,"match":"operational_default","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational pickup — Seoul departure; not a sightseeing POI"},"_role":"pickup"},{"number":2,"time":"≈ 09:30","duration":"75分","name":"水原華城","category":"ユネスコ城郭","description":"**水原華城（수원화성）— 1997年ユネスコ世界遺産登録** — 全10巻の建設記録（「華城城役儀軌」、2007年にユネスコ世界の記憶へ別途登録）が完存する、韓国唯一の城郭都市です。正祖（정조、朝鮮第22代王、在位\n\n1776〜1800年）の命により**1794〜1796年のわずか2年9か月**で築城されました。華城は、朝鮮の都を漢陽（ソウル）から水原へ移転する計画、そして1762年に父・英祖によって米びつに生き埋めにされた思悼世子を顕彰・追慕するための王のプロジェクトでした。\n\n城郭を設計したのは**丁若鏞（정약용、号・茶山）** — 実学（実用的学問）の泰斗であり朝鮮きっての学者兼エンジニアで、韓国の伝統的守備建築と中国の攻城戦防衛理論、そして当時の西洋築城技術を融合させました。\n\n丁若鏞は建設中に重石を持ち上げるための**挙重機（거중기）** — 西洋の機械原理に基づく滑車式クレーン — を発明しました。これは韓国の建設において西洋式近代工学が記録に残る形で初めて活用された事例です。\n\n城壁の全周は**5.74km**、面積130ヘクタールを囲み、41の軍事施設を備えています：4つの主要城門（北・長安門 — **韓国現存最大の王城門**、ソウルの崇礼門より大きい；南・八達門；西・華西門；東・蒼龍門）、4つの角楼、4つの指揮所、5つの監視台、5つの砲台、さらに弓射台、水門、烽火台などが点在します。\n\n本日のガイド付き散策では、**長安門（北大門）から華西門（西門、国宝第403号）までの最も写真映えする1.2kmのルート**を歩きます。保存状態の良い軍事施設が最も密集するエリアで、徒歩約25〜30分です。また八達山山頂の**西将台（西指揮所）**では、城郭最高の眺望と王の戦略的指揮位置を体感できます。\n\n水原川に架かる7連アーチの**華虹門（北水門）**は城郭で最も撮影される建造物であり、春（桜）と秋（紅葉）の時期に特に美しい景観を見せます。ツアーは城壁を徒歩で巡りますが、スケジュールが許す場合は任意で**華城御車（화성어차）**観光トラム（大人4,000ウォン、約30分、練武台→八達門ルート）もご利用いただけます。","highlights":["**1997年ユネスコ世界遺産登録** — 建設記録が完存する韓国唯一の城郭都市","朝鮮第22代王・正祖の命により1794〜1796年の2年9か月で建設","丁若鏞が韓国・中国・西洋の築城技術を融合して設計","「華城城役儀軌」建設記録 — 2007年ユネスコ世界の記憶登録","周囲5.74km、41の軍事施設","長安門（北門）― **韓国現存最大の王朝城門**","長安門→華西門 1.2km ガイド付きウォーク（写真撮影スポット最密集区間）","華虹門 7アーチ水門 ― 最も撮影される構造物","韓服着用者・毎月最終水曜日・65歳以上シニアは**無料**"],"timeUsed":["長安門付近にコーチ下車（約5分）","長安門にてグループ向け簡単オリエンテーション（約5分）","長安門→華西将台→華西門までウォーク（約25〜30分）","写真撮影タイム＋車両前に集合（約10分）","オプション：華城列車（観光トロッコ）練武台↔八達門（片道約30分；大人₩4,000）"],"whyOnRoute":"このルートのユネスコ基軸スポット ― 1794〜1796年に正祖王の命で築かれた、韓国唯一現存の城郭都市。長安門→華西門ウォーク（約1.2km）では、保存状態の良い軍事建築が最も密集しており、象徴的な華虹門7アーチ水門を75分の停車時間内で堪能できます。全長5.74kmの一周コースではなくこの区間を選んだ理由は、最も多く撮影され歴史的価値の高い区間を効率よく巡りながら、その日の他の3か所の史跡観光時間を確保するためです。また華城は、行宮（王の仮宮殿）を内部に抱え南門市場を見下ろす立地から、**水原日帰りツアー必須の要衝**でもあります。つまり水原4〜5時間のブロックで、ユネスコ世界遺産の格式・朝鮮王朝王室居所の内部空間・本格的な伝統市場のストリートフードを、車両を移動させることなく一度に体験できます。華西将台経由の長安門→華西門 1.2km城壁区間は、韓国で軍事建築の保存密度が最も高い区間であり、25〜30分の徒歩圏内に主要城門4か所・暗門5か所・水門4か所・居重機で築かれた城壁が共存しています。","visitBasics":{"hours":"城壁路は24時間通行可（城門を除く）；推奨時間は夏季09:00〜18:00・冬季09:00〜17:00；夜間開放は5〜10月の水〜日曜18:00〜21:30","closed":"年中無休（華城列車は月曜休業）","admission":"大人1,000／青少年700／子ども500ウォン（無料：6歳以下の子ども・65歳以上シニア・韓服着用者・毎月最終水曜日）。華城列車は別途4,000ウォン","walking":"中程度 ― 西将台付近に急勾配あり；各城門に階段あり；一部区間は車椅子での通行が困難"},"convenience":{"restroom":"長安門・華西門・八達門・練武台","parking":"コーチは長安門駐車場に下車；コーチ指定駐車場は練武台"},"smartNotes":{"photo":"**華虹門（北水門）**：水原川に架かる7アーチの水門 ― 春（桜）と秋（紅葉）に映える定番撮影スポット。**長安門（韓国現存最大の王朝城門）**：ゴールデンアワーに最適。**西将台（西側指揮所）**：八達山に沈む夕日との絶景。","facilities":"長安門・八達門・華城行宮広場に観光案内センターあり。場内全域に英語・韓国語の案内板設置。長安門にて華城オーディオガイドの貸し出しあり。","tip":"城壁の石畳は凹凸があるため、歩きやすい靴をご着用ください。行宮広場の韓服レンタルショップを利用すると、城郭・行宮の入場料が**無料**になります。**全長5.74kmの一周コースは2時間30分以上の余裕がない限り避けてください** ― 長安門→華西門区間が1メートルあたりの史跡密度が最も高い区間です。"},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城 — 写真1","alt":"水原華城 — ギャラリー画像1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城 — 写真2","alt":"水原華城 — ギャラリー画像2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城 — 写真3","alt":"水原華城 — ギャラリー画像3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城 — 写真4","alt":"水原華城 — ギャラリー画像4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城 — 写真5","alt":"水原華城 — ギャラリー画像5"}]},{"number":3,"time":"≈ 11:00","duration":"75分","name":"華城行宮","category":"朝鮮王朝の行宮（離宮）","description":"**華城行宮（화성행궁）— 現存する韓国最大の行宮（離宮）** — 正祖王のもと、華城城郭都市の統合計画の一環として1789年から1796年にかけて建設されました。\n\n**行宮**とは、朝鮮王朝の国王が行幸・避難・特別な儀式の際に使用した仮の離宮であり、華城行宮はその規模において温陽・北漢山・南漢山の行宮を凌いでいます。正祖王は主に、処刑された父・思悼世子の墓所（顕隆園、現在の隆陵、南方約4km）を参拝する際の宿泊のために建設し、**在位中に13回**の行幸を行いました。\n\nこれらの行幸の中で最も有名なのが**1795年の王室行列**で、6,000人の随行者と1,400頭の馬を率い、思悼世子の未亡人であり正祖の母・恵慶宮洪氏の還暦を祝いました。\n\n1795年の行列は**『園幸乙卯整理儀軌』— 2007年よりユネスコ世界の記憶に登録**されています。行宮はもともと**576間（部屋・構造スパン）**で構成され、正殿（奉壽堂）、副殿（洛南軒）、居住棟（長安軒）、厨房、軍務所、衛兵所を備えた完全な小型宮殿として機能していました。\n\n**日本統治時代（1910〜1945年）にほぼ破壊され**、日本は宮殿跡地を水原道立病院と警察署に転用しました。\n\n**復元は1996年に開始** — 原本の『華城城役儀軌』工事記録に基づき、第1期は2003年完了（奉壽堂・洛南軒・長安軒・維與宅）、第2期は2009年完了（右花館王室厨房・新豊楼正門）。復元は現在も継続中です。\n\n**重要な歴史的注記：洛南軒（낙남헌）は1796年の創建当初から現存する唯一の建物**— 日本は警察署の事務所として転用しましたが、取り壊しはしませんでした。そのため、現地で唯一の本物の木造・瓦葺き建築であり、他のすべての建物は復元です。\n\n**毎日の王室衛兵交代式**は新豊楼前にて — **火〜日曜日 午前11時**（天候次第）、約15分、無料。赤・青・黄の衣装をまとった衛兵が伝統的な太鼓や角笛とともに朝鮮時代の宮門儀式を再現します。\n\nツアーは曜日が合う場合、午前11時の儀式に合わせて到着します。韓国ドラマ**『宮廷女官チャングムの誓い』（大長今、2003年）**の撮影地 — MBC で最高視聴率 約57% を記録した朝鮮時代を代表する名作で、韓国で最も多くの時代劇が撮影された場所のひとつです。","highlights":["**現存する韓国最大の行宮（離宮）** — もともと576室","正祖王のもと、華城城郭と並行して1789〜1796年に建設","正祖王は処刑された父・思悼世子を偲び、在位中に13回の王室行幸を行った","**洛南軒＝1796年の創建から現存する唯一の建物**（他はすべて復元）","**王室衛兵交代式 火〜日曜日 午前11時 新豊楼前（無料、約15分）**","1795年の王室行列はユネスコ世界の記憶に登録されている","韓国ドラマ「宮廷女官チャングムの誓い」（2003年 MBC、最高視聴率 約57%）のロケ地","韓服着用者・65歳以上の高齢者・6歳以下のお子様は**無料**","**洛南軒（낙남헌）は1796年の創建当時から現存する唯一の建物**——日本統治時代に警察署の事務所として転用されたが、取り壊しは免れた。現在見られる他のすべての行宮の建物は、『華城城役儀軌』（2007年よりユネスコ世界の記憶に登録）に基づき1996年以降に復元されたものである"],"timeUsed":["華城城郭（華西門エリア）から徒歩約5分","新豊楼での**11:00 王宮交代式**に間に合うよう到着（約15分）","奉寿堂（正殿）＋洛南軒＋長安軒の見学（約30分）","写真撮影＋車両への集合（約15分）","新豊楼での王宮交代式（任意参加、火〜日曜11:00、約15分、無料——天候による）"],"whyOnRoute":"城郭と自然に組み合わせられる観光スポット——仮の王宮は同じユネスコ遺産内に位置し、わずか5分の距離。韓国最大の行宮（もともと576室）であり、**洛南軒は唯一の本物の当初の建物**（他は1996年以降に『華城城役儀軌』に基づき復元されたもの）。王宮交代式（火〜日曜11:00）に合わせて到着すれば無料で約15分楽しめ——これはカタログ内で最も魅力的な無料文化体験のひとつ。行宮を城郭のすぐ後に訪れることで、抽象的な軍事建築の見学が、朝鮮王朝の宮廷空間を肌で感じる体験へと昇華する——1795年に正祖王が臣下を引見した奉寿堂は、母・恵慶宮の60歳誕生日の盛大な宴（儀軌に保存された班次図巻物に描かれている）の舞台ともなった。**城郭＋行宮の共通券**は3,500ウォンで販売（別々に購入すると2,500ウォン）——水原観光の付加価値を具体的に示すアンカーとなる。新豊楼での王宮交代式（火〜日曜11:00、約15分、無料）は、ソウル発日帰り旅行の水原到着スケジュールに合わせて設定されている。","visitBasics":{"hours":"09:00〜18:00（最終入場17:30）；夏季（5〜10月）夜間開放18:00〜21:00","closed":"年中無休","admission":"大人1,500ウォン／青少年1,000ウォン／子ども700ウォン。城郭＋行宮の共通券3,500ウォン。韓服着用者・65歳以上の高齢者・6歳以下のお子様は無料","walking":"容易——宮殿の敷地はほぼ平坦で、中庭間に若干の段差あり"},"convenience":{"restroom":"正門付近、奉寿堂近く、行宮広場に設置","parking":"華城行宮公共駐車場；行宮広場有料駐車場"},"smartNotes":{"photo":"**奉寿堂（正殿）**——象徴的な正殿の撮影スポット。**洛南軒**——1796年の唯一の当初の建物（最も歴史的に真正な写真が撮れる場所）。**新豊楼での王宮交代式**（火〜日曜11:00）。新豊楼前での韓服姿——水原で最も人気の韓服写真スポット。","facilities":"観光案内センター、トイレ、ギフトショップ。行宮広場のカフェと韓服レンタル（4時間15,000〜20,000ウォン）。水原トンダク（丸鶏の炉焼き）レストランへ徒歩約5分。","tip":"**火〜日曜11:00の王宮交代式に合わせて到着（無料）**。韓服レンタルで城郭・行宮の両方が無料入場可能。**洛南軒は歴史的に最も重要な場所**——日本統治時代の取り壊しを免れた唯一の建物。月曜日は避けること——王宮交代式は火〜日曜のみ実施。"},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城","alt":"水原華城 — ギャラリー画像"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城","alt":"水原華城 — ギャラリー画像"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城","alt":"水原華城 — ギャラリー画像"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城","alt":"水原華城 — ギャラリー画像"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城","alt":"水原華城 — ギャラリー画像"}]},{"number":4,"time":"≈ 12:30","duration":"120分","name":"韓国民俗村（龍仁）","category":"民俗文化遺産の村","description":"**韓国民俗村（한국민속촌、龍仁）— 韓国初かつ最大規模の伝統民俗文化野外博物館**。水原から車で約30分、龍仁市の自然の谷地形に約991,735㎡（245エーカー／30万坪）の敷地を誇ります。\n\n**朝鮮時代後期を再現した260棟以上の伝統家屋と建造物**が韓国の全地域（ソウル、京畿、黄海、平安、咸鏡、江原、忠清、全羅、慶尚、済州）と全社会階層（庶民の農家から両班の屋敷まで）を網羅し、近代以前の韓国社会の縮図を成しています。\n\n**9つの伝統工芸工房**（鍛冶、紙すき、陶芸、機織りなど）では職人による実演を間近で見学できます。村では**公開スケジュールに沿った毎日の伝統公演**が人気で、**農楽（農民の打楽器音楽）、줄타기・ジュルタギ（綱渡り — ユネスコ無形文化遺産、滑稽な語りを交えて披露）、馬上武芸（疾走する馬上での剣技アクロバット）、朝鮮時代の伝統婚礼再現**などが楽しめます。\n\n公演時間は通常10:30／14:00／15:30（入口でご確認ください）。**体験アクティビティ**：村の池での渡し舟、乗馬、天然染色、韓服レンタル（門内で30分間の無料体験）、弓道場、書院見学。\n\nコンボチケットには子ども向けアトラクションを備えた小規模遊園地エリアも含まれます。**朝鮮時代を舞台にしたK-ドラマ時代劇（사극）のロケ地として頻繁に使用**されており、名作**「宮廷女官チャングムの誓い（大長今、2003年）」**、**「成均館スキャンダル（2010年）」**、**「ミスター・サンシャイン（2018年）」**など多数の作品が撮影されています。\n\n毎年恒例の「Welcome to Joseon」フェスティバルは春の村の風物詩。**秋（10月最後の2週間）**は両班の二階建て家屋を背景に黄金色のイチョウと紅葉の楓が彩り、写真撮影に最適な季節です。\n\nコース中最も長い滞在時間（約2時間の散策）— その日の体験の中で最も朝鮮後期の息吹を肌で感じられるスポットです。","highlights":["**韓国初かつ最大の野外博物館** 伝統民俗文化（991,735㎡／245エーカー）","韓国全地域・全社会階層を網羅する260棟以上の伝統家屋","現役の伝統工芸工房9か所（鍛冶・紙すき・陶芸・機織りなど）","**ユネスコ無形文化遺産「줄타기・ジュルタギ（綱渡り）」実演**","農楽（打楽器演奏）＋馬上武芸＋朝鮮時代の伝統婚礼再現","「宮廷女官チャングムの誓い」（MBC、最高視聴率 約57%）・「成均館スキャンダル」・「ミスター・サンシャイン」のロケ地","**10月最後の2週間＝写真撮影のベストシーズン**（黄金色のイチョウ＋紅葉の楓）","コンボチケットに含まれる小規模遊園地エリア（ファミリー向け）","**줄타기（줄타기）綱渡り** — 毎日公演 — は**2011年よりUNESCO人類無形文化遺産**：演技中に綱渡り師が地上の音楽家／MCと漫談を交わす、韓国唯一の綱渡りの伝統"],"timeUsed":["華城行宮から龍仁まで車で約30分","団体チケット購入＋入場案内（約5分）","自由散策＋伝統工芸体験（約80分）","時間が合えば公演鑑賞（農楽／줄타기／婚礼再現、約20〜30分）","車両への集合（約15分）"],"whyOnRoute":"当日最大の文化遺産ゾーン（徒歩約2時間）で、ルート中最も肌で感じられる朝鮮後期の見どころ。全国各地・各階層を再現した260棟以上の古民家、実演する職人、馬術ショー、伝統婚礼、そしてUNESCO無形文化遺産の줄타기綱渡りが、華城の軍事建築という抽象的な歴史を生きた朝鮮体験として鮮烈に描き出す。**片道30分のドライブは2時間の充実した滞在で十分に元が取れる**。韓国民俗村は**ソウル首都圏最高のサグク（時代劇）K-ドラマ撮影地**として知られ、撮影作品には『宮廷女官チャングムの誓い』（2003〜04年、全54話、MBC 最高視聴率 約57%）、『成均館スキャンダル』（2010年）、『雲が描いた月明かり』（2016年）など多数がある。韓流ファンの旅行者にとって、複数の地方に点在する個別のロケ地を巡るより、ここ一か所で得られる「本物感」の密度は圧倒的に高い。水原駅観光案内所からの無料シャトルバス（約30分）、または江南駅5番出口からの直通5001-1番バスで、ソウル発日帰りにて華城と組み合わせる最もスムーズなK-ドラマ聖地巡礼ペアが完成する。","visitBasics":{"hours":"月〜木 10:00〜18:00、金〜日・祝日 10:00〜22:00（冬期短縮 — 11〜2月 09:30〜17:30）","closed":"年中無休","admission":"大人37,000／青少年32,000／子供26,000ウォン（Visit Korea公式；コンボには遊戯施設エリアを含む）。民俗村のみの場合、大人約22,000ウォン","walking":"普通 — 広大な敷地（全域を回ると約5〜7km）；道は平坦〜緩やかな傾斜の土・砂利道"},"convenience":{"restroom":"園内各所に案内標識付きのトイレあり","parking":"専用駐車場あり — 普通車2,000ウォン、SUV／トラック3,000ウォン；観光バス用駐車スペースも完備"},"smartNotes":{"photo":"**10月下旬の2週間が両班屋敷の銀杏＋紅葉のピーク**。両班の二階建て家屋と市場通りが最も絵になるスポット。韓服レンタル＋伝統舞台はファミリー写真の人気No.1スポット。줄타기綱渡り公演はアクション満点の撮影チャンス。","facilities":"伝統的な市場の屋台では地元のおやつを販売（任実チーズピザ、鉄道ホットドッグ、ウィニビニキャンディなど）。韓国の農村料理を提供するレストランも複数あり。入口内にて韓服の無料30分体験レンタルも利用可能。","tip":"**入口で毎日の英語公演スケジュールを確認**。줄타기（UNESCO無形文化遺産・綱渡り）と農楽（農村打楽器演奏）、伝統的な朝鮮時代の婚礼再現は必見の公演。**秋の紅葉ピーク、10月20日〜11月5日がベストシーズン**。華城と組み合わせれば朝鮮テーマの充実した一日に。最低2時間は確保を；3〜4時間滞在する訪問者も多い。"},"_poi_meta":{"poi_key":"korean_folk_village_yongin","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","HereKoreaTravel","Wikipedia","Korea Tourism Organization (english.visitkorea.or.kr — Korean Folk Village official listing)","Korean Folk Village Yongin (koreanfolk.co.kr — operating hours + festival schedule + admission)","UNESCO Intangible Cultural Heritage of Humanity (Jultagi tightrope walking — 2011 inscription)","Wikipedia (Korean Folk Village — 245 acres / 260 traditional houses / 1974 founding)","Visit Korea KTO Sageuk K-Drama Filming Locations Guide (Daejanggeum/Jewel-in-the-Palace + Sungkyunkwan Scandal)"],"note":"Reference fix: Phase 1 used poi_key ''korean_folk_village''; KB canonical key is ''korean_folk_village_yongin''."},"image":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","images":["/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp"],"imageCredits":[{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","source":"atoc-korea"},{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"韓国民俗村（龍仁）","caption":"韓国民俗村（龍仁） — photo 1","alt":"韓国民俗村（龍仁） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"韓国民俗村（龍仁）","caption":"韓国民俗村（龍仁） — photo 2","alt":"韓国民俗村（龍仁） — gallery image 2"}]},{"number":5,"time":"≈ 15:30","duration":"75分","name":"スターフィールド図書館 水原","category":"モダンな文化的ランドマーク","description":"**スターフィールド図書館 水原（별마당 도서관 수원）** — **2024年1月26日にオープンしたシンセゲの旗艦「第2世代」スターフィールドモール、スターフィールド水原**内に位置しています。第5のスターフィールドモールとして、河南以外では延べ床面積最大（約334,000㎡）を誇ります。**BCHO パートナーズ（趙炳秀）**との共同設計によるもので — 同韓国建築事務所はCOEXのオリジナル・スターフィールド図書館（2017年）も手がけています — 水原の図書館は**最高22メートルの本棚**を備えた第2世代の進化形で、韓国の公共空間の中でも最も高い円筒型本棚構造のひとつです。\n\n図書館は**4フロア**（4F〜7Fの集中空間）にわたり、韓国・海外の出版物、定期刊行物、アート書籍、4Fの専用児童文学コーナーを含む**大規模な書籍・雑誌コレクション**を所蔵しています。\n\n**無料・一般公開** — ライブラリーカード不要、入場料無料、モール営業時間中（毎日10:00〜22:00）いつでも利用可能。書籍の貸出はできません（館内閲覧のみ）。特徴的な施設として：韓国インディー＋国際ジャズ／クラシックロックのヴァイナルをセレクトした**ヴァイナルレコード試聴ラウンジ**；韓国現代アーティストとのコラボによるアトリウム内の**月替わりアート展示**；そして**中央アトリウムの季節限定桜インスタレーション（3月〜4月）** — 数千枚のピンクLED花びらが舞い、水原で最も写真に収められる春の名所のひとつです。\n\n隣接モールの施設には：韓国料理のファストフード（5,000〜10,000ウォン）からプレミアムダイニング（40,000ウォン以上）まで30店舗以上を擁する**イートピアフードホール（B1F）**；別途有料（約25,000〜35,000ウォン）の**アクアフィールド水原ウォーターパーク＋韓国式スパ（B1〜2F）**；**トイキングダム（4F、韓国最大のおもちゃ店）**；そしてCGV/MEGABOXのデュアルシネマが含まれます。\n\n**無料スターフィールドシャトルバス**が水原駅4番出口から10〜15分おきに運行（乗車時間約10分）— 公共交通機関からのアクセスに最も便利な手段です。朝鮮王朝ゆかりの3スポットを巡った後の「現代韓国」への転換点として、午後遅い時間帯の天候リスクを回避できる屋内フィナーレを提供します。","highlights":["**シンセゲの旗艦第2世代スターフィールドモール — 2024年1月26日オープン**","BCHO パートナーズ設計（2017年COEXオリジナル・スターフィールド図書館の設計者でもある）","**22メートルの本棚を備えた4フロアの図書館** — 韓国で最も高い円筒型本棚のひとつ","約70,000冊の書籍＋雑誌が無料で利用可能","セレクトコレクションを揃えたヴァイナルレコード試聴ラウンジ","アトリウムの桜LED花びらインスタレーション（3月〜4月）","イートピアフードホール（30店舗以上）、アクアフィールドウォーターパーク、トイキングダム、CGV/MEGABOXシネマ","水原駅4番出口から無料スターフィールドシャトル（約10分）","モール営業時間：毎日10:00〜22:00"],"timeUsed":["龍仁／韓国民俗村から車で15分","モール＋図書館ウォーキングツアー（約45〜50分）","図書館またはフードホールでのカフェ休憩（約15分）","車への集合","オプション：ヴァイナルLPカフェラウンジ（5F、約₩18,500 ドリンク＋ヘッドフォン＋LPレコードプレーヤー利用込み；約30〜45分）"],"whyOnRoute":"城郭＋宮殿＋民俗村という3つの歴史スポットを巡った後の「現代韓国」への切り替えとなります。シンセゲの旗艦第2世代スターフィールドモールは2024年1月26日にオープン；22メートルの本棚とヴァイナル試聴コーナーを備えた4フロアの図書館がアーキテクチャルハイライトです。**完全屋内スポット** — 午後遅い時間帯の天候リスクを回避し、あらゆる世代（子ども → トイキングダム；10代 → ヴァイナル＋本棚；大人 → カフェ＋ショッピング）が楽しめます。スターフィールド図書館は**ソウル中心部以外のソウル首都圏で最もInstagramに投稿される屋内空間**（2024〜25年韓国トラベルメディア調査より） — 22メートルの本棚（ソウルCOEXの13mと比較）はモール4フロア（4F〜7Fのアトリウム吹き抜け）を貫き、屋上レベルには**カナダ人小説家・デザイナーのダグラス・コープランドによる「ザ・プラネッツ」インスタレーション**が水原限定で展示されています。**入場無料、会員登録不要、撮影可** — 当日の華城／行宮／民俗村といった有料スポットを訪れた後の、気軽なフォトスポットとして最適です。水原駅からのアクセス：地下鉄1号線で花西駅1/4番出口（地下鉄約3分、徒歩8分）、または無料スターフィールドシャトルバス（水原駅4番出口から10〜15分間隔で運行）。","visitBasics":{"hours":"モール10:00〜22:00；図書館はモール営業時間中いつでも利用可能","closed":"月1〜2回の休館日あり（通常は月曜日 — 訪問前にオンラインで確認を）","admission":"**図書館無料**（モール全体無料入場；ショッピングは都度払い；アクアフィールドウォーターパークは別途約25,000〜35,000ウォン）","walking":"簡単 — 全フロア間にエスカレーターとエレベーターあり；車椅子・ベビーカー対応"},"convenience":{"restroom":"各フロアに複数のトイレあり；おむつ交換台完備のファミリーフレンドリー施設","parking":"地下駐車場 約5,000台分；ショッピングモールで30,000ウォン以上のお買い上げで最初の3時間無料；団体用コーチ駐車スペースあり"},"smartNotes":{"photo":"**22メートルの本棚がそびえるライブラリー中央アトリウム** — 定番の撮影スポット、4Fギャラリーから見下ろすアングルが最高。**ヴァイナルレコードラウンジ**でレトロな雰囲気を楽しめます。**アトリウムの桜のインスタレーション（3〜4月）** — SNSで話題の季節限定フォトスポット。クリスマスツリー（12月）。ファミリー写真には4Fのキッズコーナーがおすすめ。","facilities":"B1Fのイートピアフードホール（30店舗以上、5,000〜40,000ウォン）、4Fのトイキングダム、B1〜2Fのアクアフィールドウォーターパーク、T-Joy・CGV・MEGABOXシネマ、無料Wi-Fi、多言語カスタマーサービス、主要店舗での税金還付カウンター。","tip":"**ライブラリーは入場無料** — 非常にお得な観光スポット。**水原駅4番出口からの無料スターフィールドシャトル**が最も便利なアクセス手段（10〜15分間隔）。**22メートルの本棚 = 韓国最大の図書館本棚**（ゲストへのインパクトとして必ずお伝えください）。**桜のインスタレーション（3〜4月）**は季節の必見スポット。土曜日の午後は混雑のピークとなるため避けることをおすすめします。月に1〜2日の休館日があるため、訪問前にオンラインでご確認ください。"},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-05-21","sources":["Starfield official","VisitKorea","Shinsegae press release","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"スターフィールド図書館 水原","caption":"スターフィールド図書館 水原 — photo 1","alt":"スターフィールド図書館 水原 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"スターフィールド図書館 水原","caption":"スターフィールド図書館 水原 — photo 2","alt":"スターフィールド図書館 水原 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"スターフィールド図書館 水原","caption":"スターフィールド図書館 水原 — photo 3","alt":"スターフィールド図書館 水原 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"スターフィールド図書館 水原","caption":"スターフィールド図書館 水原 — photo 4","alt":"スターフィールド図書館 水原 — gallery image 4"}]},{"number":6,"time":"≈ 17:00","duration":"60分","name":"ソウルへ戻る","category":"帰路","description":"朝の集合場所と同じポイント（弘大入口駅8番出口または明洞駅2/4番出口）での**降車**にて中心部ソウルへコーチで戻ります。到着は通常**交通状況により18:00〜18:30頃** — 京釜高速道路の夕方の渋滞により、朝の移動と比べて15〜20分程度余分にかかる場合があります。","highlights":["京釜高速道路経由でコーチにて帰路","弘益大学前またはミョンドンにてお降ろし（朝の乗車地点と同じ）","通常到着時刻 18:00〜18:30"],"timeUsed":["水原からソウルまでコーチで移動（約60分）","指定地点にてお降ろし"],"whyOnRoute":"帰路のご案内 — お降ろし場所は、お客様の利便性と時間の確実性を重視して選定しています。夕方早めの時間帯にソウル中心部でお降ろしすることで、ご自由な夕食の計画に十分な時間をお取りいただけます。","visitBasics":{},"convenience":{},"smartNotes":{"tip":"最終到着時刻は金曜夜・週末の交通状況によって異なります。混雑が激しい日は、お降ろしまでに15〜20分程度余分にかかる場合があります。"},"_poi_meta":{"poi_key":"OPS_return","verified":false,"match":"operational_implicit","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational stop (return)"},"_role":"dropoff"}],"routeFlowStops":[{"name":"ソウル","type":"origin","theme":"出発"},{"name":"水原華城","type":"primary","theme":"ユネスコ世界遺産の城郭"},{"name":"華城行宮","type":"primary","theme":"世界遺産の宮殿"},{"name":"韓国民俗村（龍仁）","type":"primary","theme":"世界遺産の村"},{"name":"スターフィールド ライブラリー 水原","type":"secondary","theme":"現代の韓国"},{"name":"ソウル","type":"return","theme":"帰路"}],"routePhases":[{"phase":"往路","duration":"≈ 1時間","description":"ソウル → 京釜高速道路経由で水原市へ"},{"phase":"世界遺産の半日コース","duration":"≈ 3時間","description":"水原華城の城壁と行宮は、いずれも徒歩圏内に位置しています。"},{"phase":"民俗村","duration":"約2時間30分","description":"車で30分、龍仁（ヨンイン）の韓国民俗村へ向かい、野外公園を散策します。"},{"phase":"現代への締めくくり","duration":"約1時間30分","description":"水原（スウォン）に戻り、スターフィールド図書館とモールのフードホールへ。"},{"phase":"帰路","duration":"約1時間","description":"水原 → ソウル。"}],"routeShapeIntro":{"title":"この日の流れ","subtitle":"ソウル南部に広がるコンパクトな三角ルート——水原のユネスコ城郭都市、龍仁の野外朝鮮時代村、そして水原の旗艦モダンモール——を巡ることで、250年の歴史を横断する韓国の公共空間を4か所で体感できます。午前中は城壁、昼は茅葺き屋根、午後は硝子と書物の世界へ。"},"whyTourWorks":{"bestFor":["韓国初訪問で、1日でユネスコ世界遺産（華城）と野外文化遺産村の両方を訪れたい方","韓国ドラマ・歴史好きの旅行者——民俗村は数多くの大河歴史ドラマのロケ地として知られています","写真撮影を楽しむ旅行者——スターフィールド図書館の高さ22mの書棚が4フロアに広がる吹き抜けは、韓国で最も多く撮影される現代的空間のひとつです","ガイド付きペースで終日約4〜5kmの歩行に対応できるカップルや大人のご家族","ソウル中心部の宮殿にとどまらず、京畿道（キョンギド）の幅広い文化遺産を楽しみたい旅行者"],"lessIdealFor":["移動に制限のある方——城壁には急勾配の区間・城門の階段・不規則な石畳があります","ベビーカー利用のグループ（民俗村の道は概ねフラットですが、城壁はベビーカー向きではありません）","当日の乗り継ぎフライトに余裕が必要な方（渋滞リスクを考慮すると、ソウル到着は約18:00になります）","ソウル中心部の宮殿（景福宮・昌徳宮）を訪れたい方——このツアーは京畿道エリアに限定されています","ショッピングメイン目的の旅行者——スターフィールド水原は図書館目的での立ち寄りであり、ショッピングではありません（フードホール＋散策のみ、約60〜90分の予算）"],"routeLogicSections":[{"title":"このルートの設計意図","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"ユネスコ遺産＋民俗村＋図書館、1日で","detail":"これらはいずれも京畿道を代表する日帰り観光スポットですが、ソウルからバスや地下鉄でのアクセスが不便な場所ばかりです。このツアーは入場料込みの貸切バスで3か所をひとつのループにまとめることで、複雑な計画や乗り継ぎの手間を省きます。"},{"label":"定番の「城塞＋図書館」ツアーより充実した内容","detail":"水原のツアーの多くは、行宮か民俗村のどちらかを省略しています。このツアーは両方を組み込んでいるため、朝鮮時代の物語がしっかりと伝わります――城壁、その内側にある王の居所、そしてその城が統治した村の暮らしを、実際に目で見ることができます。"},{"label":"入場無料、解説は有料","detail":"スターフィールド図書館は個人での入館は無料ですが、ガイドと一緒だとはるかに充実した体験ができます。なぜショッピングモールがこれを建てたのか（新世界のMZ世代戦略）、COEXのオリジナルとどう異なるのか、読書中の利用者を邪魔せずに最高の撮影スポットはどこかを、ガイドが丁寧に解説してくれます。"},{"label":"通年対応ルート","detail":"南怡島や雪岳山のように季節によって大きく左右されるツアーとは異なり、このコースはどんな天候でも楽しめます。城塞・宮殿・民俗村はいずれも冬季も営業しており、図書館は屋内施設です。紅葉や桜の時期が合わない場合の代替プランとして最適です。"}]},{"title":"実際の歩行負担について","icon":"footprints","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","items":[{"label":"城壁：その日の最もきつい区間","detail":"長安門から華西門までの1km区間には急な坂道と門の階段があります。歩きやすい靴が必須です。この区間は車椅子での通行が困難です。"},{"label":"民俗村：約2時間、ほぼ平坦","detail":"敷地は広いですが、道は平坦からなだらかな傾斜です。歩行時間は約2時間を見込んでください。座って鑑賞できる公演の休憩も上手に活用しましょう。ベビーカーでの入園も可能です。"},{"label":"行宮＆スターフィールド：楽なコース","detail":"宮殿の敷地は平坦で、中庭に若干の段差があります。スターフィールド図書館は全4フロアにエスカレーターとエレベーターが完備されています。"}]},{"title":"天候や季節の変化に応じて","icon":"cloud-sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"4月上旬の桜","detail":"城壁沿いには桜の木が並んでおり、4月上旬が最高の撮影シーズンです。宮殿でのハンボクレンタルを利用すれば、その日最高の写真が撮れます。"},{"label":"7〜8月の夏の暑さ","detail":"城壁には日陰がほとんどありません。この時期は民俗村の木陰のある道や屋内のスターフィールドを中心に過ごす時間が増えます。こまめな水分補給が欠かせません。"},{"label":"12〜2月の冬の寒さ","detail":"寒い日は城壁の散策が短くなります。民俗村の屋内公演スケジュールも少なくなります。スターフィールドが自然と長めに滞在するスポットになります。"}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"含まれるもの","preview":"ソウルからの往復コーチ送迎、英語対応ツアーガイド、水原華城…","content":["ソウルからの往復コーチ送迎、英語対応ツアーガイド、水原華城入場料、華城行宮入場料、韓国民俗村入場料。","含まれないもの：食事、飲み物、民俗村のオプション体験（韓服レンタル、弓道）、チップ。","スターフィールド図書館の入場は無料です。"]},{"id":"pickup","title":"送迎について","preview":"弘大入口駅（8番出口）約08:00発、または明洞駅（2番または4番出口）約08:30発。","content":["弘大入口駅（8番出口）約08:00発、または明洞駅（2番または4番出口）約08:30発。","10分前にお集まりください。","ホテルへの送迎はございません。集合場所のみとなります。","遅刻者はご参加いただけません。"]},{"id":"walking","title":"徒歩と地形について","preview":"中程度。","content":["中程度。","城壁ウォークは上り坂の石段や凸凹した路面を含みます。通常、全長5.7kmのループのうち約1kmを歩きます。","民俗村は広大な屋外施設（約245エーカー）ですが、平坦な地形です。","スターフィールド図書館では、フロア間の移動に階段とエスカレーターを使用します。","歩きやすいシューズが必須です。"]},{"id":"what","title":"服装と持ち物について","preview":"歩きやすいクローズドトゥシューズ、夏は日よけ帽子、春・秋は重ね着…","content":["歩きやすいクローズドトゥシューズ、夏は日よけ帽子、春・秋は重ね着、冬は防寒コート（城壁は風が強いため）。","カメラ、水分、軽食。","昼食および民俗村のオプション体験のための現金。"]},{"id":"cancellation","title":"キャンセルについて","preview":"ツアー開始の24時間前まで無料キャンセル可能です。","content":["ツアー開始の24時間前まで無料キャンセル可能です。","当日のキャンセルおよびノーショー（無断不参加）は返金不可です。"]},{"id":"children","title":"お子様とバリアフリーについて","preview":"お子様も大歓迎です。特に民俗村はファミリー向けで、乗馬ショーや…","content":["お子様も大歓迎です。特に民俗村はファミリー向けで、乗馬ショーや伝統的な遊びをお楽しみいただけます。","ベビーカーは行宮（ヘングン）と民俗村のメインパスを通行できます。","城壁沿いの散策路には階段があり、ベビーカーでの通行には適していません。","城壁区間は車椅子でのアクセスが限られています。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"季節のご案内をご覧ください"},"tomorrow":{"temp":"—","label":"季節のご案内をご覧ください"},"_seasonalSummary":"Suwon and Yongin track Seoul''s weather closely (about 30 km south). Plan for hot, humid summers and cold, dry winters; spring and autumn are the most comfortable.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"5–22°C","notes":"Cherry blossoms along the fortress wall in early–mid April."},{"season":"Summer (Jun–Aug)","range":"22–32°C","notes":"Hot and humid; bring sun protection and water."},{"season":"Autumn (Sep–Nov)","range":"8–22°C","notes":"Best season — clear skies, mild temperatures."},{"season":"Winter (Dec–Feb)","range":"-5 to 6°C","notes":"Cold winds on the fortress wall; library is indoors and warm."}]},"seasonalVariations":[{"season":"春","description":"華城（ファソン）城壁沿いと民俗村の桜が見頃を迎えます。初秋には水原華城文化祭りが盛大に開催されます。"},{"season":"夏","description":"民俗村の水まつりや、選定された夜に行宮（ヘングン）のライトアップが行われます。"},{"season":"秋","description":"城壁沿いの紅葉が美しく、韓国民俗村では伝統婚礼や収穫祭のデモンストレーションが楽しめるベストシーズンです。"},{"season":"冬","description":"雪化粧した城壁は韓国を代表する絶景のひとつ。民俗村では冬の伝統行事（キムジャン、オンドル焚き）が体験できます。"}],"bookingTrustItems":[{"icon":"check-circle","title":"地元認定オペレーター","description":"完全保険付きの公認韓国ツアーオペレーター","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"ルートの専門家","description":"一般的なループコースではなく、丁寧に調整されたルート","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"厳選されたグループサイズ","description":"ルートに最適化された人数構成","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"すぐに","title":"即時確認","detail":"旅程概要付き予約確認"},{"timing":"12時間前","title":"12時間前リマインダー","detail":"天気情報とルートの変更案内"},{"timing":"前日夜","title":"最終送迎情報","detail":"正確なお迎え時間とドライバー連絡先"},{"timing":"ツアー当日の朝","title":"当日ルートメモ","detail":"現地の最新状況に基づく朝のご案内"},{"timing":"ツアー中","title":"各立ち寄りスポットのヒント","detail":"各スポットでのリアルタイムガイダンス"},{"timing":"ツアー終了後","title":"ツアー後サポート","detail":"フォローアップとおすすめ"}],"staticQuestions":[{"id":"q1","question":"入場料は含まれていますか？","answer":"はい。水原華城・華城行宮・韓国民俗村の入場料はすべて含まれています。スターフィールドライブラリーはどなたでも無料です。韓服レンタル・弓道体験・その他の民俗村オプションアクティビティはお客様のご負担となります。"},{"id":"q2","question":"昼食は含まれていますか？","answer":"いいえ。昼食は通常、スターフィールド水原のフードホール（種類豊富、₩10,000〜₩20,000）での自由時間中か、城塞近くの水原の小さな食堂（水原式カルビやチキン）でお取りいただきます。"},{"id":"q3","question":"城壁はどのくらい歩きますか？","answer":"全長5.7kmのループのうち約1kmで、通常は長安門（チャンガンムン）と華西門（ファソムン）の間のセクションを歩き、いくつかの城楼と烽火台も含みます。全ループは3時間以上かかるため、このツアーの行程には含まれていません。"},{"id":"q4","question":"スターフィールド図書館に1時間まるごと費やす価値はありますか？","answer":"初めての訪問者には十分な価値があります――それ自体が建築的な見どころです。フリータイムは遅めのランチ、コーヒー、またはスターフィールド水原モール（2024年1月にオープンした韓国の旗艦・第2世代スターフィールド）のショッピングにもお使いいただけます。"},{"id":"q5","question":"民俗村で韓服（チマチョゴリ）はレンタルできますか？","answer":"はい、韓服のレンタルは追加料金（通常1〜2時間で₩10,000〜₩20,000）で現地にてご利用いただけます。韓服を着用すると、伝統体験アクティビティの割引も受けられます。ガイドがレンタルブースへご案内します。"},{"id":"q6","question":"水原＋ワウジョンサツアーとの違いはありますか？","answer":"はい。このツアーでは韓国民俗村（主要な文化遺産スポット）が追加され、スターフィールド図書館が現代的なスポットとして含まれます。ワウジョンサバージョンでは民俗村がなく、代わりに龍仁の巨大仏像がある寺院が含まれます。遺産の深みを重視するならこのツアーを、仏教彫刻を重視するならワウジョンサバージョンをお選びください。"},{"id":"first-time","question":"水原・龍仁への初めての訪問者にとって良い選択肢ですか？","answer":"はい――ユネスコ世界遺産（水原華城）、文化遺産村（韓国民俗村）、朝鮮時代の宮殿（行宮）、現代的な写真スポット（スターフィールド図書館）を1日で巡りたい旅行者に最適な初回向けコースです。ソウル中心部の宮殿と重複することなく、韓国文化の4つの対照的な側面をカバーしています。地理的にはルートが水原〜龍仁エリアに収まっています。"},{"id":"walking","question":"歩くのは大変ですか？","answer":"合計約4〜5kmを歩くアクティブな1日です。華城の城壁が最もきつい区間で、長安門と華西門の間の1kmを歩きます。急な勾配、門での階段、凸凹した歴史的な路面があります。韓国民俗村では平坦〜緩やかな傾斜の道を約2時間歩きます（270棟以上の家屋が広がっています）。行宮とスターフィールド図書館は歩きやすい屋内・中庭の路面です。履き慣れた靴が必須です。"},{"id":"family","question":"このツアーはファミリーに向いていますか？","answer":"歩き多めのスポットを含む10時間の1日をこなせるお子さまがいるご家族には向いています。民俗村はファミリーの目玉――270棟以上の伝統家屋、乗馬ショー、韓国ドラマのロケ地、週末の伝統的な婚礼が楽しめます。行宮での韓服レンタルは楽しい写真タイムです（韓服着用者は城郭への入場が無料になります）。城壁ではベビーカーは難しいですが、スターフィールドと民俗村では問題ありません。"},{"id":"seniors","question":"高齢の方でも快適に参加できますか？","answer":"階段や凸凹した地面に慣れているアクティブなシニアの方にのみお勧めします。城壁が最もきつい区間で、急勾配と階段により一部区間は車椅子での移動が困難な場合があります。シニアの方は歩きやすい城壁区間を歩き、指揮所はスキップすることができます。民俗村の道は平坦〜緩やかな傾斜で、ほとんどの方が歩けます。行宮はほぼ平坦です。スターフィールドはエスカレーター・エレベーターが完備されています。"},{"id":"children","question":"推奨される最低年齢は何歳ですか？","answer":"10歳以上が最適です――城壁の歩行（凸凹した路面）、民俗村のアクティブな散策、そして長い1日が含まれます。小さなお子さまも抱っこ紐で参加できますが、1kmの城壁歩きと2時間の民俗村は6〜9歳のお子さまを疲れさせる場合があります。民俗村の乗馬ショーや伝統的な公演は年長のお子さまに大人気です。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_