","Hwaseong Haenggung Palace","Korean Folk Village","Starfield Library Suwon"],"competing_products":["seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library","seoul-suwon-hwaseong-waujeongsa-starfield","pocheon-sanjeong-lake-herb-island-art-valley"],"anchor_poi_keys":["hwaseong_fortress","hwaseong_haenggung","korean_folk_village","starfield_library_suwon"],"enrichment_batch":"17e","enrichment_date":"2026-04-29","enrichment_kb_version":"1.27","enrichment_target_kb_version":"1.28","profile_version_pre":6,"profile_version_post":6,"schema_version":7,"patch_type":"polish_existing_pv6_to_a_grade","patch_target":"12 substantive stop instances across 3 tours; Batch 11 era authoring → A-grade pv=6 PASS (universal source-attribution gap closed; Suwon-Hwaseong-route + Starfield-library-photo-stop + Korean-Folk-Village-K-drama-set + Gwangmyeong-cave-mining-heritage + Waujeongsa-syncretic-buddhism + Suwon-galbi-tongdak-street patterns introduced)"},"itinerary_variants":[],"_publication":{"schema_version":"v4_canonical","last_modified":"2026-04-28","version_history":["v11","v12","v13","v14","v15"],"fix_passes":{"v12":"P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned","v13":"P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 canonical (no Tailwind in data)","v14":"P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing","v15":"P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.","v17_schema_unification":{"date":"2026-04-28","description":"Phase 1: Standardized matching_profile scores to the current 0-1 float scale used by match_tours.matching_profile.","fi