  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","locale":"es","product_id":"seoul-suwon-hwaseong-folk-village-starfield-library","seo":{"pageTitle":"Suwon Hwaseong, Pueblo Folclórico y Biblioteca Starfield | AtoC Korea","metaDescription":"Excursión de un día en grupo reducido de 10 horas desde Seúl: Fortaleza Suwon Hwaseong (Patrimonio UNESCO), Palacio Hwaseong Haenggung, Pueblo Folclórico Coreano (Yongin) y Biblioteca Starfield Suwon.","primaryKeywords":["Excursión a Suwon Hwaseong desde Seúl","Excursión de un día al Pueblo Folclórico Coreano","Excursión a la Biblioteca Starfield Suwon","Excursión de un día por lugares UNESCO en Corea"],"ogImage":"https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"Excursión de un día desde Seúl a Suwon Hwaseong, Pueblo Folclórico Coreano y Biblioteca Starfield | AtoC Korea"},"catalog_card":{"thumbnail":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","title":"Suwon: Hwaseong, Pueblo Folclórico y Starfield","priceLabel":"","shortCardDescription":"Una excursión cultural de día en grupo reducido desde Seúl hasta la provincia de Gyeonggi, que abarca cuatro facetas contrastantes del patrimonio coreano y la vida moderna: la Fortaleza Suwon Hwaseong (Patrimonio de la Humanidad UNESCO, con murallas y puertas del siglo XVIII), el restaurado Palacio Hwaseong Haenggung con sus recreaciones de la era Joseon, el envolvente Pueblo Folclórico Coreano al aire libre en Yongin, y la espectacular Biblioteca Starfield Suwon de cuatro plantas. 10 horas con transporte y entradas incluidos.","tags":["small_group","cultura","unesco","patrimonio","biblioteca","folk_village","day_trip"],"rating":0,"reviewCount":0,"slug":"seoul-suwon-hwaseong-folk-village-starfield-library","subtitle":"Una excursión cultural de día en grupo reducido desde Seúl hasta la provincia de Gyeonggi, que abarca cuatro facetas contrastantes del patrimonio coreano y la vida moderna: la declarada Patrimonio de la Humanidad…","region":"Gyeonggi-do (al sur de Seúl)","duration":"10 horas","stopsCount":6,"badges":["Grupo Reducido","Cultura","UNESCO","Patrimonio","Biblioteca","Pueblo Folclórico","Excursión de un día"],"heroImage":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp"},"headlineLine1":"Día del Patrimonio de Suwon","headlineLine2":"Hwaseong, Pueblo Folclórico y Starfield","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null},"hero":{"imageUrl":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","imagePosition":"center 35%","tagline":"La única fortaleza amurallada de Corea, un pueblo folclórico y la biblioteca que arrasa en Instagram","pills":["Grupo pequeño","Cultura"],"meta":{"duration":"10 horas","region":"Gyeonggi-do (al sur de Seúl)","stops":"6 paradas","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"Descripción general"},{"id":"itinerary","label":"Itinerario"},{"id":"details","label":"Detalles"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reseñas"}],"glanceItems":[{"icon":"camera","label":"Valor fotográfico","value":"Excelente","level":5},{"icon":"mountain","label":"Pintoresco","value":"Bueno","level":4},{"icon":"footprints","label":"Caminata","value":"Alto","level":4},{"icon":"cloud-rain","label":"Seguridad bajo la lluvia","value":"Bueno","level":4},{"icon":"users","label":"Apto para familias","value":"Bueno","level":4},{"icon":"gauge","label":"Equilibrio","value":"Equilibrado","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 1","caption":"Fortaleza Hwaseong de Suwon — photo 1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"Pueblo Folclórico Coreano (Yongin)","alt":"Pueblo Folclórico Coreano (Yongin) — gallery image 1","caption":"Pueblo Folclórico Coreano (Yongin) — photo 1"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Biblioteca Starfield Suwon","alt":"Biblioteca Starfield Suwon — gallery image 1","caption":"Biblioteca Starfield Suwon — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 2","caption":"Fortaleza Hwaseong de Suwon — photo 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 3","caption":"Fortaleza Hwaseong de Suwon — photo 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 4","caption":"Fortaleza Hwaseong de Suwon — photo 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 5","caption":"Fortaleza Hwaseong de Suwon — photo 5"},{"id":8,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Fortaleza Hwaseong de Suwon","alt":"Fortaleza Hwaseong de Suwon — gallery image 6","caption":"Fortaleza Hwaseong de Suwon — photo 6"},{"id":9,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"Pueblo Folclórico Coreano (Yongin)","alt":"Pueblo Folclórico Coreano (Yongin) — gallery image 2","caption":"Pueblo Folclórico Coreano (Yongin) — photo 2"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Biblioteca Starfield Suwon","alt":"Biblioteca Starfield Suwon — gallery image 2","caption":"Biblioteca Starfield Suwon — photo 2"},{"id":11,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Biblioteca Starfield Suwon","alt":"Biblioteca Starfield Suwon — gallery image 3","caption":"Biblioteca Starfield Suwon — photo 3"},{"id":12,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Biblioteca Starfield Suwon","alt":"Biblioteca Starfield Suwon — gallery image 4","caption":"Biblioteca Starfield Suwon — photo 4"}],"itineraryStops":[{"number":1,"time":"≈ 08:00","duration":"10 min","name":"Salida desde Seúl","category":"Recogida y salida","description":"Recogida en uno de los dos puntos de encuentro del centro de Seúl: **Salida 8 de la Estación Universidad Hongik** (zona Hongdae, Línea 2 del Metro de Seúl/Airport Express) o **Salida 2 o 4 de la Estación Myeongdong** (Línea 4 del Metro de Seúl). Confirme la hora exacta de recogida y la ubicación al reservar — el itinerario está diseñado para comenzar temprano y llegar a la Fortaleza Hwaseong antes de la afluencia de grupos turísticos coreanos de media mañana. \n\nAproximadamente **1 hora en autobús hacia el sur hasta Suwon** por la Autopista Gyeongbu — la histórica ciudad fortaleza del Rey Jeongjo de Joseon, quien construyó Hwaseong (1794-1796) para honrar y proteger la tumba de su padre ejecutado, el Príncipe de la Corona Sado. Tráfico fluido de lunes a viernes por la mañana; el tráfico de fin de semana añade un margen de 15-20 minutos. El autobús dispone de aire acondicionado y la mayoría de los asientos están equipados con carga USB.","highlights":["Recogida en la Universidad Hongik (Línea 2) o Myeongdong (Línea 4) ~08:00","1 hora en autobús hacia el sur hasta Suwon por la Autopista Gyeongbu","Autobús con aire acondicionado + carga USB","Diseñado para llegar temprano a la Fortaleza Hwaseong antes de la afluencia de grupos turísticos"],"timeUsed":["Encuentro en el punto de recogida designado en Seúl (~5 min para embarcar)","Trayecto de 1 hora en autobús hasta Suwon (~60 min con tráfico fluido)"],"whyOnRoute":"Una salida desde Seúl a las 09:00 permite al grupo llegar a la Fortaleza Hwaseong antes de la afluencia del mediodía y se adapta al horario de actuaciones vespertinas del Pueblo Folclórico Coreano (recreación de la ceremonia de boda con Hanbok, espectáculo ecuestre, percusión de granjeros Nong-ak).","visitBasics":{},"convenience":{},"smartNotes":{"tip":"Confirme la hora exacta de recogida y el punto de encuentro al reservar — la hora punta matutina de Seúl (07:00-09:00) hace que la puntualidad sea fundamental. Lleve agua, protector solar y calzado cómodo para caminar por la muralla de la fortaleza."},"_poi_meta":{"poi_key":"OPS_seoul_pickup_default","verified":false,"match":"operational_default","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational pickup — Seoul departure; not a sightseeing POI"},"_role":"pickup"},{"number":2,"time":"≈ 09:30","duration":"75 min","name":"Fortaleza Hwaseong de Suwon","category":"Fortaleza UNESCO","description":"**Suwon Hwaseong (수원화성) — Patrimonio Mundial de la UNESCO desde 1997** — es la única ciudad amurallada de Corea conservada junto con su registro de construcción original en 10 volúmenes (Hwaseong Seongyeok Uigwe, inscrito por separado en el Registro de la Memoria del Mundo de la UNESCO en 2007). Construida **entre 1794 y 1796 en tan solo 2 años y 9 meses** bajo el reinado del Rey Jeongjo (정조, 22.º rey Joseon, r. \n\n1776-1800), Hwaseong fue el proyecto del rey para trasladar la capital Joseon de Hanyang (Seúl) a Suwon — y para honrar a su padre el Príncipe de la Corona Sado, quien fue encerrado vivo en un cofre de arroz por su propio padre, el Rey Yeongjo, en 1762. \n\nLa fortaleza fue diseñada por **Jeong Yak-yong (정약용, también conocido como Dasan)** — el principal académico-ingeniero de Joseon perteneciente a la escuela Silhak (aprendizaje práctico) — quien integró la arquitectura defensiva tradicional coreana con la teoría china de defensa ante asedios y la emergente ciencia occidental de fortificación. \n\nJeong Yak-yong inventó el **geojunggi (거중기)** — una grúa de poleas y motones basada en principios mecánicos occidentales — para elevar piedras pesadas durante la construcción; constituye el primer uso documentado de ingeniería moderna de estilo occidental en la construcción coreana. \n\nLa muralla completa de la fortaleza tiene **5,74 km de perímetro** y encierra 130 hectáreas con 41 estructuras estratégicas: 4 puertas principales (Janganmun al norte — la **puerta real existente más grande de Corea**, mayor que la Sungnyemun de Seúl; Paldalmun al sur; Hwaseomun al oeste; Changnyongmun al este), 4 torres angulares, 4 puestos de mando, 5 plataformas de vigilancia, 5 baterías de cañones, además de plataformas de tiro con arco, compuertas y torres de señales. \n\nEl paseo guiado de hoy recorre el **tramo más fotogénico de 1,2 km entre Janganmun (puerta principal norte) y Hwaseomun (puerta oeste, Tesoro Nacional N.º 403)** — la mayor densidad de estructuras militares conservadas, con ~25-30 minutos de caminata. Añada la visita al **Seojangdae (Puesto de Mando Oeste)** en lo alto del Monte Paldalsan para disfrutar del punto más elevado de la fortaleza y del puesto de mando estratégico del rey. \n\n**Hwahongmun (compuerta norte)** con sus 7 arcos sobre el Arroyo Suwoncheon es la estructura más fotografiada de la fortaleza — especialmente en primavera (flores de cerezo) y otoño (follaje). El grupo de visita recorre la muralla a pie; si el horario lo permite, hay disponible un tranvía turístico opcional **Hwaseong Trolley** (4.000 KRW adultos, ~30 min, ruta Yeonmudae→Paldalmun).","highlights":["**Patrimonio Mundial de la UNESCO desde 1997** — la única ciudad amurallada de Corea que conserva los registros originales de su construcción","Construida entre 1794 y 1796 en 2 años y 9 meses bajo el reinado del Rey Jeongjo (22.º rey Joseon)","Diseñada por Jeong Yak-yong combinando ciencia de fortificación coreana, china y occidental","Registro de construcción Hwaseong Seongyeok Uigwe — Memoria del Mundo de la UNESCO 2007","5,74 km de perímetro, 41 estructuras militares estratégicas","Puerta norte de Janganmun — **la puerta real existente más grande de Corea**","Paseo guiado de 1,2 km Janganmun → Hwaseomun (tramo con mayor densidad fotográfica)","Compuerta de 7 arcos Hwahongmun — la estructura más fotografiada","GRATIS para portadores de hanbok + último miércoles del mes + mayores de 65 años"],"timeUsed":["Bajada del autocar cerca de Janganmun (~5 min)","Breve orientación grupal en Janganmun (~5 min)","Caminata Janganmun → Hwaseomun pasando por Hwaseo Janggak (~25-30 min)","Tiempo para fotos + reagrupamiento en el vehículo (~10 min)","Tranvía turístico Hwaseong Yeolcha opcional Yeonmudae↔Paldalmun (~30 min solo ida; ₩4.000 adulto)"],"whyOnRoute":"El ancla UNESCO del recorrido — la única ciudad fortaleza amurallada que queda en Corea, construida entre 1794 y 1796 bajo el reinado del rey Jeongjo. El trayecto a pie Janganmun → Hwaseomun (~1,2 km) ofrece la mayor densidad de estructuras militares preservadas + la icónica compuerta de 7 arcos Hwahongmun en una parada de 75 minutos. Se eligió sobre el circuito completo de 5,74 km porque este tramo concentra la sección más fotografiada y de mayor riqueza histórica, dejando tiempo para las otras tres paradas patrimoniales del día. Hwaseong es también el **ancla obligatoria de cualquier excursión de un día a Suwon**, ya que rodea físicamente el palacio Haenggung y domina el Mercado Nammun, lo que significa que un único bloque de 4-5 horas en Suwon puede combinar credenciales de Patrimonio Mundial UNESCO, la interioridad de una residencia real joseon y auténtica gastronomía callejera de mercado tradicional sin necesidad de reposicionar el vehículo. El tramo de muralla de 1,2 km Janganmun → Hwaseomun pasando por Hwaseo Janggak es el corredor de arquitectura militar preservada de mayor densidad de Corea (4 puertas principales + 5 puertas secretas + 4 compuertas + murallas construidas con el Geojunggi coexisten en 25-30 minutos de caminata).","visitBasics":{"hours":"Camino de la muralla abierto 24 horas (sin puertas); horario recomendado 09:00-18:00 verano / 09:00-17:00 invierno; horario nocturno mayo-oct mié-dom 18:00-21:30","closed":"Abierto todo el año (Tranvía Hwaseong cerrado los lunes)","admission":"Adultos 1.000 / Jóvenes 700 / Niños 500 KRW (GRATIS: niños ≤6 años, mayores de 65, portadores de hanbok, último miércoles del mes). Tranvía Hwaseong por separado 4.000 KRW","walking":"Moderado — la muralla tiene tramos empinados en Seojangdae; escaleras en las puertas; algunos tramos de difícil acceso para silla de ruedas"},"convenience":{"restroom":"En Janganmun, Hwaseomun, Paldalmun y Yeonmudae","parking":"Bajada del autocar en el aparcamiento de Janganmun; aparcamiento designado para autocares en Yeonmudae"},"smartNotes":{"photo":"**Hwahongmun (compuerta norte)** con 7 arcos sobre el arroyo Suwoncheon — la toma icónica, especialmente en primavera (flores de cerezo) y otoño (follaje). **Janganmun (la puerta real existente más grande de Corea)** a la hora dorada. **Seojangdae (puesto de mando oeste)** con puesta de sol sobre la montaña Paldalsan.","facilities":"Centro de Información al Visitante en Janganmun + Paldalmun + Plaza Hwaseong Haenggung. Señalización en inglés y coreano en todo el recinto. Alquiler de audioguía de Hwaseong disponible en Janganmun.","tip":"Use calzado cómodo — las piedras de la muralla son irregulares. Las tiendas de alquiler de hanbok en la Plaza Haenggung ofrecen entrada GRATUITA a la fortaleza y al palacio. **Evite el circuito completo de 5,74 km a menos que disponga de más de 2,5 horas** — el tramo Janganmun → Hwaseomun ofrece la mayor densidad patrimonial por metro."},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 1","alt":"Fortaleza Hwaseong de Suwon — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 2","alt":"Fortaleza Hwaseong de Suwon — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 3","alt":"Fortaleza Hwaseong de Suwon — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 4","alt":"Fortaleza Hwaseong de Suwon — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 5","alt":"Fortaleza Hwaseong de Suwon — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 6","alt":"Fortaleza Hwaseong de Suwon — gallery image 6"}]},{"number":3,"time":"≈ 11:00","duration":"75 min","name":"Palacio Hwaseong Haenggung","category":"Palacio Real Destacado de Joseon","description":"**Hwaseong Haenggung (화성행궁) — el haenggung (palacio destacado) existente más grande de Corea** — fue construido entre 1789 y 1796 bajo el rey Jeongjo como parte del plan urbano unificado de la fortaleza Hwaseong. \n\nUn **haenggung** es una residencia real temporal/destacada utilizada por los reyes de Joseon durante viajes, refugio en tiempos de guerra o ceremonias especiales; el Hwaseong Haenggung supera en escala a los haenggung de Onyang, Bukhansan y Namhansan. El rey Jeongjo lo construyó principalmente para pernoctar durante sus visitas a la tumba de su padre ejecutado, el Príncipe de la Corona Sado (Hyeollyungwon, actualmente llamada Tumba Real Yungneung, a 4 km al sur) — una peregrinación que realizó **13 veces durante su reinado**. \n\nEl más famoso de estos viajes fue la **procesión real de 1795** con 6.000 acompañantes y 1.400 caballos, celebrando el 60.º cumpleaños de Lady Hyegyeong (la madre del rey y viuda de Sado). \n\nLa procesión de 1795 está documentada en el **Wonhaeng Eulmyo Jeongni Uigwe — inscrito en el Registro Memoria del Mundo de la UNESCO desde 2007**. El palacio constaba originalmente de **576 kan (habitaciones/crujías estructurales)** y funcionaba como una completa residencia real en miniatura con sala del trono (Bongsudang), sala secundaria (Naknamheon), aposentos residenciales (Janganheon), cocinas, oficinas militares y cuarteles de la guardia. \n\n**Destruido en gran parte durante el período colonial japonés** (1910-1945), cuando los japoneses convirtieron el recinto del palacio en el Hospital Provincial de Suwon y la Comisaría de Policía. \n\n**La restauración comenzó en 1996** siguiendo el registro de construcción original del Hwaseong Seongyeok Uigwe; la primera fase se completó en 2003 (Bongsudang, Naknamheon, Janganheon, Yuyeotaek) y la segunda fase en 2009 (cocina real Wuhwagwan, puerta de entrada Sinpung-nu). La restauración continúa hoy en día. \n\n**Nota histórica clave: Naknamheon (낙남헌) es el ÚNICO edificio que sobrevivió de la construcción original de 1796** — los japoneses lo convirtieron en oficinas de la Comisaría de Policía, pero no lo demolieron. Por tanto, es la única estructura auténtica original de madera y teja en el lugar; todos los demás edificios son reconstrucciones. \n\n**Ceremonia diaria de cambio de guardia real** en la puerta Sinpungnu — **martes a domingo a las 11:00 h** (según las condiciones meteorológicas), ~15 min, GRATIS. Recrea la ceremonia de la puerta del palacio de la era Joseon con guardias en uniformes rojo, azul y amarillo con tambores y cuernos tradicionales. \n\nEl horario del tour está programado para llegar a la ceremonia de las 11:00 h cuando el día de la semana lo permite. Filmado para el K-drama **''La joya del palacio'' (Daejanggeum, 2003)** — el icónico éxito de la era Joseon con un índice máximo de ~57% en MBC — convirtiéndolo en uno de los lugares sageuk más filmados de Corea.","highlights":["**El haenggung (palacio destacado) existente más grande de Corea** — originalmente 576 habitaciones","Construido entre 1789 y 1796 junto a la Fortaleza Hwaseong bajo el rey Jeongjo","El rey Jeongjo realizó 13 peregrinaciones reales aquí para honrar a su padre ejecutado, el Príncipe de la Corona Sado","**Naknamheon = ÚNICA estructura original de 1796 que se conserva** (las demás son reconstrucciones)","**Ceremonia de cambio de guardia real mar-dom a las 11:00 h en la puerta Sinpungnu (GRATIS, ~15 min)**","Procesión Real de 1795 documentada en la Memoria del Mundo de la UNESCO","Lugar de filmación del k-drama ''La Joya del Palacio'' (2003 en MBC, índice máximo ~57%)","GRATIS para personas con hanbok + mayores de 65 años + niños de 6 años o menos","**Naknamheon (낙남헌) es el ÚNICO edificio que sobrevive de la construcción original de 1796** — las autoridades de la era colonial japonesa lo convirtieron en oficinas de la Comisaría de Policía, pero no lo demolieron; todas las demás estructuras del Haenggung visibles hoy en día son reconstrucciones posteriores a 1996 basadas en el Hwaseong Seongyeok Uigwe (Memoria del Mundo de la UNESCO desde 2007)"],"timeUsed":["A 5 minutos a pie de la Fortaleza Hwaseong (zona de Hwaseomun)","Llegue a tiempo para la **Ceremonia del Cambio de Guardia Real a las 11:00** en Sinpungnu (~15 min)","Recorrido por el Salón del Trono Bongsudang + Naknamheon + Janganheon (~30 min)","Tiempo para fotos + reagrupamiento en el vehículo (~15 min)","Ceremonia opcional del Cambio de Guardia Real en la Puerta Sinpungnu (mar-dom 11:00, ~15 min, GRATIS — sujeto a condiciones meteorológicas)"],"whyOnRoute":"Se complementa de forma natural con la muralla de la fortaleza — la residencia real temporal está DENTRO del mismo sitio de la UNESCO, a solo 5 minutos. El haenggung más grande de Corea (originalmente 576 habitaciones), con **Naknamheon como la única estructura auténtica original** (las demás son reconstrucciones posteriores a 1996 basadas en el Hwaseong Uigwe). Programe la llegada para la Ceremonia del Cambio de Guardia Real (mar-dom 11:00), que es GRATUITA y dura ~15 min — uno de los atractivos de experiencia cultural gratuita más destacados del catálogo. Visitar el Haenggung inmediatamente después de las murallas de la fortaleza convierte una lección abstracta de arquitectura militar en una experiencia espacial real de la Corea joseoniana — el mismo salón del trono Bongsudang donde el Rey Jeongjo recibió a sus funcionarios en 1795 también acogió el espléndido banquete del 60.º cumpleaños de su madre, Lady Hyegyeong (representado en los rollos de pintura cortesana Banchado conservados en el Uigwe). Se vende una **entrada combinada Fortaleza + Haenggung** por 3.500 KRW (frente a 2.500 KRW por separado) — un atractivo tangible de valor añadido para la parada en Suwon. La Ceremonia del Cambio de Guardia Real en la Puerta Sinpungnu (mar-dom 11:00, ~15 min, GRATIS) está programada para coincidir con la mayoría de los horarios de llegada a Suwon en las excursiones de un día desde Seúl.","visitBasics":{"hours":"09:00-18:00 (última entrada 17:30); horario nocturno de verano mayo-oct 18:00-21:00","closed":"Abierto todo el año","admission":"Adulto 1.500 / Joven 1.000 / Niño 700 KRW. Entrada combinada Fortaleza + Haenggung 3.500 KRW. GRATIS para personas con hanbok, mayores de 65 años, niños de 6 años o menos","walking":"Fácil — los terrenos del palacio son mayormente planos con algunos escalones entre los patios"},"convenience":{"restroom":"En la entrada principal, cerca de Bongsudang y en la Plaza Haenggung","parking":"Aparcamiento público de Hwaseong Haenggung; aparcamientos de pago en la Plaza Haenggung"},"smartNotes":{"photo":"**Salón Principal Bongsudang** — la icónica toma del salón del trono. **Naknamheon** — la única estructura original de 1796 (la fotografía más auténtica desde el punto de vista histórico). **Ceremonia del Cambio de Guardia Real en la Puerta Sinpungnu** (mar-dom 11:00). Personas con hanbok frente a Sinpungnu — el punto más popular de Suwon para fotografiarse con hanbok.","facilities":"Centro de información para visitantes, aseos, tienda de regalos. Cafeterías y alquiler de hanbok en la Plaza Haenggung (15.000-20.000 KRW por 4 horas). Restaurantes de Suwon Tongdak (pollo asado entero) a 5 minutos a pie.","tip":"**Programe la llegada para la Ceremonia del Cambio de Guardia Real a las 11:00 de mar a dom (GRATIS)**. El alquiler de hanbok incluye entrada GRATUITA tanto a la Fortaleza como al Haenggung. **Naknamheon es EL punto históricamente más importante** — la única estructura no reconstruida, que sobrevivió a la demolición durante la época colonial japonesa. Evite los lunes — la Ceremonia del Cambio de Guardia Real se celebra únicamente de mar a dom."},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 1","alt":"Palacio Hwaseong Haenggung — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 2","alt":"Palacio Hwaseong Haenggung — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 3","alt":"Palacio Hwaseong Haenggung — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 4","alt":"Palacio Hwaseong Haenggung — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 5","alt":"Palacio Hwaseong Haenggung — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 6","alt":"Palacio Hwaseong Haenggung — gallery image 6"}]},{"number":4,"time":"≈ 12:30","duration":"120 min","name":"Pueblo Folclórico Coreano (Yongin)","category":"Pueblo del Patrimonio Folclórico","description":"**Pueblo Folclórico Coreano (한국민속촌, Yongin) — el primer y mayor museo al aire libre de cultura folclórica tradicional de Corea**, con una extensión de ~991.735 m² (245 acres / 300.000 pyeong) en un terreno de valle natural en la ciudad de Yongin, a ~30 minutos en coche de Suwon. \n\n**Más de 260 casas y estructuras tradicionales reproducidas de la tardía Dinastía Joseon** representan cada región de Corea (Seúl, Gyeonggi, Hwanghae, Pyongan, Hamgyong, Gangwon, Chungcheong, Jeolla, Gyeongsang, Jeju) y cada clase social (desde granjas de campesinos hasta residencias de la clase culta yangban) — un tapiz sociológico completo de la Corea premoderna. \n\n**9 talleres artesanales tradicionales** (herrería, fabricación de papel, cerámica, tejido, etc.) albergan artesanos que demuestran sus oficios en vivo. El pueblo es famoso por sus **actuaciones tradicionales diarias** con horario publicado: **Nong-ak (música de percusión de agricultores), Jultagi (acrobacia en cuerda floja — Patrimonio Cultural Inmaterial de la Humanidad de la UNESCO, interpretado con narración cómica), artes marciales a caballo (acrobacias montadas con balanceos de espada al galope) y recreaciones de ceremonias de bodas tradicionales de Joseon**. \n\nLos horarios de las actuaciones son generalmente a las 10:30 / 14:00 / 15:30 — confirmar en la entrada. **Actividades interactivas**: paseos en barca por el estanque del pueblo, equitación, teñido natural de telas, alquiler de hanbok (prueba gratuita de 30 min dentro de la entrada), campo de tiro con arco, visita a la Escuela Confuciana. \n\nUna modesta sección de parque de atracciones con juegos para niños está incluida con las entradas combinadas. **Utilizado con frecuencia como escenario de rodaje de sageuk (producciones históricas) de k-dramas de la era Joseon** — entre ellos el icónico **La joya en el palacio (Daejanggeum, 2003)**, **Escándalo en Sungkyunkwan (2010)**, **Mr. Sunshine (2018)** y muchos otros. \n\nEl festival anual ''Bienvenido a Joseon'' es el evento primaveral emblemático del pueblo; **el otoño (las últimas dos semanas de octubre)** es el momento fotográficamente óptimo, con el dorado follaje de los ginkgos y los arces rojos junto a la casa de dos pisos yangban. \n\nEl bloque de tiempo individual más largo del recorrido (~2 horas caminando) — la experiencia más auténtica de la tardía era Joseon en el día.","highlights":["**El primer y mayor museo al aire libre de Corea** de cultura folclórica tradicional (991.735 m² / 245 acres)","Más de 260 casas tradicionales que representan cada región y clase social coreana","9 talleres artesanales tradicionales activos (herrería, papel, cerámica, tejido)","**Demostraciones de Jultagi (acrobacia en cuerda floja), Patrimonio Cultural Inmaterial de la Humanidad de la UNESCO**","Percusión Nong-ak de agricultores + artes marciales a caballo + recreaciones de bodas de Joseon","Lugar de rodaje de La joya en el palacio (MBC, índice máximo ~57%), Escándalo en Sungkyunkwan, Mr. Sunshine","**Las últimas 2 semanas de octubre = el momento fotográfico cumbre** (ginkgos dorados + arces rojos)","Sección de parque de atracciones modesta incluida con entradas combinadas (apta para familias)","**Jultagi (줄타기) acrobacia en cuerda floja** — representado diariamente — es **Patrimonio Cultural Inmaterial de la Humanidad de la UNESCO desde 2011**: la única tradición coreana de cuerda floja en la que el equilibrista mantiene un diálogo cómico con un músico/presentador a nivel del suelo durante toda la actuación"],"timeUsed":["30 min en coche desde Hwaseong Haenggung hasta Yongin (~30 min)","Venta de entradas grupales + orientación de acceso (~5 min)","Paseo autoguiado por el pueblo + talleres de artesanía (~80 min)","Asistencia a espectáculos según horario (Nong-ak / Jultagi / recreación de boda tradicional, ~20-30 min)","Reagrupación en el vehículo (~15 min)"],"whyOnRoute":"El bloque patrimonial más importante del día (~2 horas a pie) y la parada más visceralmente del Joseon tardío en el recorrido. Más de 260 casas que representan cada región y clase social, artesanos en activo, espectáculos ecuestres, ceremonias de boda tradicionales y el Jultagi —Patrimonio Inmaterial de la UNESCO— de acrobacia en cuerda floja; todo ello dramatiza la abstracción curada de la arquitectura militar de Hwaseong en una experiencia del Joseon vivo y visceral. **El trayecto de 30 min en cada sentido queda compensado por un ancla de 2 horas**. El Pueblo Folk Coreano es el **escenario de producción de sageuk K-drama por excelencia en el Gran Seúl** — sus créditos de rodaje incluyen ''La joya en el palacio / Daejanggeum'' (2003-04 en MBC, índice máximo ~57% en 54 episodios), ''Sungkyunkwan Scandal'' (2010), ''Moonlight Drawn by Clouds'' (2016) y muchas otras. Para los viajeros impulsados por el Hallyu, esto ofrece más autenticidad por hora que visitar localizaciones de rodaje individuales dispersas por varias provincias coreanas. Un autobús lanzadera gratuito desde el Centro de Visitantes de la Estación de Suwon (~30 min) o el autobús directo 5001-1 desde la Salida 5 de la Estación de Gangnam hacen de este el par ancla K-drama operativamente más fluido con Hwaseong en un solo día partiendo desde Seúl.","visitBasics":{"hours":"Lun-Jue 10:00-18:00; Vie-Dom y festivos 10:00-22:00 (horario reducido en invierno — nov-feb 09:30-17:30)","closed":"Abierto todo el año","admission":"Adulto 37.000 / Joven 32.000 / Niño 26.000 KRW (oficial de Visit Korea; la entrada combinada incluye la sección de atracciones). Solo Pueblo Folk ~22.000 KRW adulto","walking":"Moderado — recinto amplio (~5-7 km si se explora por completo); los caminos son llanos o con suave pendiente de tierra y grava"},"convenience":{"restroom":"Múltiples aseos distribuidos por todo el recinto, debidamente señalizados","parking":"Aparcamiento propio — turismos 2.000 KRW, SUV/camiones 3.000 KRW; aparcamiento para autocares de grupo disponible"},"smartNotes":{"photo":"**Las dos últimas semanas de octubre son el momento álgido por los ginkgos dorados y los arces** en el recinto de la mansión noble. La casa de dos plantas yangban y la calle del mercado son los rincones más ricos visualmente. El alquiler de hanbok + el arena tradicional generan las fotografías familiares más populares. El espectáculo de acrobacia en cuerda floja Jultagi es una gran oportunidad fotográfica de alta acción.","facilities":"Los puestos del mercado callejero tradicional venden aperitivos locales (pizza de queso de Imsil, perritos calientes de ferrocarril, caramelos Winibini). Varios restaurantes con servicio en mesa que ofrecen menús de estilo rural coreano. Prueba gratuita de 30 min de alquiler de hanbok dentro de la entrada.","tip":"**Consulte el horario diario de espectáculos en inglés en la entrada** — el Jultagi (acrobacia en cuerda floja, Patrimonio Inmaterial de la UNESCO) y el Nong-ak (percusión campesina) + la recreación de boda tradicional del Joseon son los espectáculos imprescindibles. **La mejor visita: del 20 de octubre al 5 de noviembre** por el pico del follaje otoñal. Combínelo con la Fortaleza Hwaseong para una jornada temática coherente sobre el Joseon. Permita un mínimo de 2 horas; algunos visitantes pasan fácilmente 3-4 horas."},"_poi_meta":{"poi_key":"korean_folk_village_yongin","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","HereKoreaTravel","Wikipedia","Korea Tourism Organization (english.visitkorea.or.kr — Korean Folk Village official listing)","Korean Folk Village Yongin (koreanfolk.co.kr — operating hours + festival schedule + admission)","UNESCO Intangible Cultural Heritage of Humanity (Jultagi tightrope walking — 2011 inscription)","Wikipedia (Korean Folk Village — 245 acres / 260 traditional houses / 1974 founding)","Visit Korea KTO Sageuk K-Drama Filming Locations Guide (Daejanggeum/Jewel-in-the-Palace + Sungkyunkwan Scandal)"],"note":"Reference fix: Phase 1 used poi_key ''korean_folk_village''; KB canonical key is ''korean_folk_village_yongin''."},"image":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","images":["/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp"],"imageCredits":[{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","source":"atoc-korea"},{"url":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-44-02.webp","location":"Pueblo Folclórico Coreano (Yongin)","caption":"Pueblo Folclórico Coreano (Yongin) — photo 1","alt":"Pueblo Folclórico Coreano (Yongin) — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/korean-folk-village/chatgpt-image-2026-5-9-11-59-38.webp","location":"Pueblo Folclórico Coreano (Yongin)","caption":"Pueblo Folclórico Coreano (Yongin) — photo 2","alt":"Pueblo Folclórico Coreano (Yongin) — gallery image 2"}]},{"number":5,"time":"≈ 15:30","duration":"75 min","name":"Biblioteca Starfield Suwon","category":"Hito Cultural Moderno","description":"**Biblioteca Starfield Suwon (별마당 도서관 수원)** — ubicada dentro de **Starfield Suwon, el centro comercial Starfield de «segunda generación» insignia de Shinsegae, inaugurado el 26 de enero de 2024** como el quinto centro Starfield y el de mayor superficie bruta fuera de Hanam (~334.000 m²). Diseñada en colaboración con **BCHO Partners (Cho Byoung-soo)** — la firma coreana también responsable de la Biblioteca Starfield original en COEX (2017) — la biblioteca de Suwon representa la iteración de segunda generación con **estanterías de hasta 22 metros de altura**, entre las estructuras de estanterías cilíndricas más altas en cualquier espacio público de Corea. \n\nLa biblioteca ocupa **4 plantas** (espacio de 4F a 7F) y alberga **una amplia colección de libros y revistas**, incluyendo publicaciones coreanas e internacionales, publicaciones periódicas, libros de arte y una sección dedicada a la literatura infantil en la 4.ª planta. \n\n**GRATUITA y abierta al público** — sin tarjeta de biblioteca, sin cuota de entrada, accesible durante todo el horario comercial (10:00-22:00 todos los días). Los libros no pueden prestarse (solo lectura en el recinto). Características distintivas: **Salón de escucha de discos de vinilo** con selección de indie coreano + jazz internacional/rock clásico en vinilo; **exposición de arte rotativa mensual** en el espacio del atrio en colaboración con artistas contemporáneos coreanos; e **instalación estacional de flores de cerezo en el atrio central (marzo-abril)** con miles de pétalos LED rosas — uno de los rincones más fotografiados de Suwon en primavera. \n\nLas instalaciones adyacentes del centro comercial incluyen: **Patio de comidas Eatopia (B1F)** con más de 30 restaurantes, desde comida rápida coreana (5.000-10.000 KRW) hasta restaurantes de alta gama (40.000+ KRW); **Parque acuático Aquafield Suwon + spa coreano (B1-2F)** con entrada de pago aparte ~25.000-35.000 KRW; **Toy Kingdom (4.ª planta, la mayor juguetería de Corea)**; y una configuración de cine doble CGV/MEGABOX. \n\n**El autobús lanzadera gratuito de Starfield** sale desde la salida 4 de la estación de Suwon cada 10-15 min (~10 min de trayecto) — el acceso más sencillo desde el transporte público. El contrapeso de la «Corea moderna» tras tres paradas del patrimonio joseonés, que ofrece un cierre cubierto en interiores y amortigua cualquier riesgo meteorológico de última hora de la tarde.","highlights":["**El centro comercial Starfield de 2.ª generación insignia de Shinsegae — inaugurado el 26 de enero de 2024**","Diseñado por BCHO Partners (también diseñadores de la Biblioteca Starfield original del COEX en 2017)","**Biblioteca de 4 plantas con estanterías de 22 metros** — entre las estanterías cilíndricas más altas de Corea","Amplia colección de lectura de acceso GRATUITO","Salón de escucha de discos de vinilo con colección seleccionada","Instalación de pétalos LED de flores de cerezo en el atrio (marzo-abril)","Patio de comidas Eatopia (más de 30 restaurantes), parque acuático Aquafield, Toy Kingdom, cine CGV/MEGABOX","Lanzadera gratuita de Starfield desde la salida 4 de la estación de Suwon (~10 min)","Horario del centro comercial: 10:00-22:00 todos los días"],"timeUsed":["A 15 minutos en coche desde Yongin / Aldea Popular Coreana","Recorrido a pie por el centro comercial y la biblioteca (~45-50 min)","Descanso en cafetería en la biblioteca o en el patio de comidas (~15 min)","Reagrupación en el vehículo","Salón cafetería de vinilos LP opcional (5.ª planta, ~₩18.500 incl. bebida + auriculares + acceso a tocadiscos de vinilo; ~30-45 min)"],"whyOnRoute":"El contrapeso de la «Corea moderna» tras tres paradas patrimoniales (fortaleza + palacio + aldea popular). El centro comercial Starfield de 2.ª generación insignia de Shinsegae se inauguró el 26 de enero de 2024; la biblioteca de cuatro plantas con estanterías de 22 m y sección de escucha de vinilos es el punto arquitectónico destacado. **Parada totalmente en interiores** — amortigua cualquier riesgo meteorológico de última hora de la tarde y ofrece un atractivo multigeneracional genuino (niños → Toy Kingdom; adolescentes → vinilo + estanterías; adultos → cafetería + compras). La Biblioteca Starfield es el **espacio interior más fotografiado en Instagram del Gran Seúl fuera del centro de la ciudad** (según encuestas de medios de viaje coreanos 2024-25) — las estanterías de 22 m (frente a los 13 m del COEX de Seúl) abarcan 4 plantas del centro comercial (vacío del atrio de 4F a 7F), y la **instalación «The Planets» a nivel de azotea del novelista y diseñador canadiense Douglas Coupland** es exclusiva de la ubicación de Suwon. **Entrada GRATUITA, sin membresía, fotografías permitidas** — lo que convierte esta parada en un cierre fotográfico sin complicaciones tras las entradas de pago de Hwaseong/Haenggung/Aldea Popular a lo largo del día. Desde la estación de Suwon: Línea de metro 1 hasta la estación Hwaseo, salidas 1/4 (~3 min en metro, 8 min a pie), o autobús lanzadera gratuito de Starfield (cada 10-15 min desde la salida 4 de la estación de Suwon).","visitBasics":{"hours":"Centro comercial 10:00-22:00; biblioteca accesible durante todo el horario comercial","closed":"1-2 días de cierre mensual (normalmente los lunes — verificar en línea antes de la visita)","admission":"**Biblioteca GRATUITA** (entrada gratuita a todo el centro comercial; compras de pago según consumo; parque acuático Aquafield con entrada aparte ~25.000-35.000 KRW)","walking":"Fácil — escaleras mecánicas y ascensores entre todas las plantas; accesible para sillas de ruedas y cochecitos en todo el recinto"},"convenience":{"restroom":"Múltiples baños en cada planta; apto para familias con zonas de cambio de pañales","parking":"Estacionamiento subterráneo ~5.000 plazas; primeras 3 horas GRATIS con compra en el centro comercial de 30.000 KRW o más; zona de autobuses para grupos"},"smartNotes":{"photo":"**Atrio central de la biblioteca con estanterías de 22 metros** — la foto icónica, mejor desde la galería del piso 4 mirando hacia abajo. **Salón de Discos de Vinilo** para estética retro. **Instalación de flor de cerezo en el atrio (marzo-abril)** — foto de temporada viral. Árbol de Navidad (diciembre). Sección infantil en el piso 4 para fotos familiares.","facilities":"Patio de comidas Eatopia B1F (más de 30 restaurantes, 5.000-40.000 KRW), Toy Kingdom piso 4, parque acuático Aquafield B1-2F, cines T-Joy + CGV + MEGABOX, WiFi gratuito, atención al cliente multilingüe, mostradores de devolución de impuestos en las principales tiendas.","tip":"**La biblioteca es GRATIS** — atracción de valor excepcional. **Lanzadera gratuita de Starfield desde la Salida 4 de la Estación de Suwon** es el acceso más fácil (cada 10-15 min). **Estanterías de 22 metros = las estanterías de biblioteca más altas de Corea** (mencionarlo a los visitantes para mayor impacto). **Instalación de flor de cerezo en marzo-abril** es lo imprescindible de temporada. Evitar los sábados por la tarde (máxima afluencia). 1-2 días de cierre mensual — verificar en línea antes de la visita."},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-05-21","sources":["Starfield official","VisitKorea","Shinsegae press release","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Biblioteca Starfield Suwon","caption":"Biblioteca Starfield Suwon — photo 1","alt":"Biblioteca Starfield Suwon — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Biblioteca Starfield Suwon","caption":"Biblioteca Starfield Suwon — photo 2","alt":"Biblioteca Starfield Suwon — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Biblioteca Starfield Suwon","caption":"Biblioteca Starfield Suwon — photo 3","alt":"Biblioteca Starfield Suwon — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Biblioteca Starfield Suwon","caption":"Biblioteca Starfield Suwon — photo 4","alt":"Biblioteca Starfield Suwon — gallery image 4"}]},{"number":6,"time":"≈ 17:00","duration":"60 min","name":"Regreso a Seúl","category":"Regreso","description":"Autobús de regreso al centro de Seúl, con **bajada en los mismos puntos de encuentro de la mañana** (Salida 8 de la Estación Universidad Hongik o Salidas 2/4 de la Estación Myeongdong). Llegada normalmente **entre las 18:00 y las 18:30 según el tráfico** — el tráfico de última hora de la tarde en la Autopista Gyeongbu puede añadir un margen de 15-20 min respecto al trayecto de la mañana.","highlights":["Regreso en autocar por la Autopista Gyeongbu","Bajada en la Universidad Hongik o Myeongdong (mismo punto de recogida matutina)","Llegada habitual entre las 18:00 y las 18:30"],"timeUsed":["Trayecto en autocar de Suwon a Seúl (~60 min)","Bajada en el punto designado"],"whyOnRoute":"Logística de regreso — el punto de bajada se elige por la comodidad del huésped y la certeza horaria. La bajada en el centro de Seúl al inicio de la tarde deja tiempo para planificar la cena de forma independiente.","visitBasics":{},"convenience":{},"smartNotes":{"tip":"La llegada final depende del tráfico del viernes por la tarde / fin de semana; en días de mucho tráfico, la bajada puede añadir entre 15 y 20 min."},"_poi_meta":{"poi_key":"OPS_return","verified":false,"match":"operational_implicit","kb_version":"v1.14","verified_date":"2026-04-29","note":"Operational stop (return)"},"_role":"dropoff"}],"routeFlowStops":[{"name":"Seúl","type":"origin","theme":"Salida"},{"name":"Fortaleza Hwaseong de Suwon","type":"primary","theme":"Fortaleza UNESCO"},{"name":"Palacio Hwaseong Haenggung","type":"primary","theme":"Palacio Patrimonial"},{"name":"Pueblo Folclórico Coreano (Yongin)","type":"primary","theme":"Pueblo Patrimonial"},{"name":"Biblioteca Starfield Suwon","type":"secondary","theme":"Corea Moderna"},{"name":"Seúl","type":"return","theme":"Regreso"}],"routePhases":[{"phase":"Ida","duration":"≈ 1 hora","description":"Seúl → ciudad de Suwon por la Autopista Gyeongbu."},{"phase":"Media jornada de patrimonio","duration":"≈ 3 horas","description":"Murallas de Hwaseong de Suwon y palacio Haenggung, todos a poca distancia a pie entre sí."},{"phase":"Pueblo tradicional","duration":"≈ 2,5 horas","description":"Conduzca 30 minutos hasta el Pueblo Folclórico Coreano de Yongin y explore el parque al aire libre."},{"phase":"Epílogo moderno","duration":"≈ 1,5 horas","description":"Regrese a Suwon para visitar la Biblioteca Starfield y el patio de comidas del centro comercial."},{"phase":"Regreso","duration":"≈ 1 hora","description":"Suwon → Seúl."}],"routeShapeIntro":{"title":"Cómo transcurre este día","subtitle":"Un compacto triángulo al sur de Seúl — la ciudad fortaleza UNESCO de Suwon, el pueblo joseon al aire libre de Yongin y el moderno centro comercial insignia de Suwon — que suma un recorrido de cuatro paradas por el espacio público coreano a lo largo de 250 años. Murallas por la mañana, tejados de paja al mediodía, vidrio y libros al final de la tarde."},"whyTourWorks":{"bestFor":["Visitantes que llegan a Corea por primera vez y desean conocer un Sitio del Patrimonio Mundial de la UNESCO (Hwaseong) y un pueblo del patrimonio al aire libre en un solo día","Viajeros apasionados por los k-dramas y la historia, que reconocerán los escenarios del Pueblo Folclórico utilizados en importantes series históricas","Viajeros fotógrafos — el atrio de cuatro plantas de la Biblioteca Starfield con estanterías de 22 m es uno de los espacios contemporáneos más fotografiados de Corea","Parejas y familias de adultos que puedan caminar ≈4-5 km a lo largo del día a un ritmo guiado","Viajeros que prefieren la variedad patrimonial de la provincia de Gyeonggi antes que permanecer en los palacios del centro de Seúl"],"lessIdealFor":["Viajeros con movilidad reducida — la muralla de la fortaleza tiene tramos empinados, escaleras en las puertas y pavimento irregular","Grupos con cochecitos de bebé (los caminos del Pueblo Folclórico son mayormente planos, pero la muralla no es apta para cochecitos)","Cualquier persona que necesite un margen ajustado para tomar un vuelo el mismo día (regreso a Seúl ≈ 18:00 con riesgo de tráfico)","Visitantes que desean conocer los palacios centrales de Seúl (Gyeongbokgung, Changdeokgung) — este recorrido se desarrolla en Gyeonggi","Viajeros enfocados en las compras en centros comerciales — Starfield Suwon figura aquí por la biblioteca, no por el comercio (solo patio de comidas y paseo, presupuesto ≈60-90 min)"],"routeLogicSections":[{"title":"Por qué esta ruta está diseñada de esta manera","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"UNESCO + pueblo folclórico + biblioteca, en un solo día","detail":"Estos son tres de los destinos de excursión más visitados de Gyeonggi, y cada uno resulta difícil de alcanzar en autobús o metro desde Seúl. El recorrido los combina en un único circuito en autocar con las entradas incluidas, ahorrándole la planificación y los transbordos."},{"label":"Más sustancioso que el recorrido estándar de ''fortaleza + biblioteca''","detail":"Muchos tours por Suwon omiten el Palacio Haenggung o el Pueblo Folclórico. Este incluye ambos, y eso es lo que hace que la historia de la era Joseon realmente cobre sentido: ves la muralla, la residencia del rey en su interior y la vida del pueblo que fue construido para gobernar."},{"label":"Entrada gratuita, contexto de pago","detail":"La Biblioteca Starfield es de entrada libre por cuenta propia, pero resulta mucho más enriquecedora con un guía que pueda explicar por qué un centro comercial la construyó (la estrategia de Shinsegae para la generación MZ), en qué se diferencia del original de COEX y cuáles son los mejores ángulos fotográficos sin molestar a los lectores."},{"label":"Ruta disponible todo el año","detail":"A diferencia de los viajes a la Isla Nami o a Seoraksan, muy marcados por las estaciones, este itinerario funciona con cualquier clima. La fortaleza, el palacio y el pueblo folclórico operan en invierno; la biblioteca es interior. Una buena alternativa cuando el follaje otoñal o los cerezos en flor no están en su mejor momento."}]},{"title":"Cómo se siente realmente el esfuerzo al caminar","icon":"footprints","iconBg":"bg-esmeralda-50/80","iconColor":"text-emerald-600","items":[{"label":"Muralla de la fortaleza: la sección más exigente del día","detail":"El 1 km recorrido entre Janganmun y Hwaseomun tiene tramos empinados y escaleras en las puertas. Calzado cómodo imprescindible. Este tramo es difícil para sillas de ruedas."},{"label":"Pueblo Folclórico: ≈2 horas, principalmente llano","detail":"El recinto es amplio, pero los caminos son llanos o con pendiente suave. Calcule ≈2 horas de caminata; las pausas para ver las actuaciones sentado son de gran ayuda. Apto para cochecitos de bebé."},{"label":"Haenggung y Starfield: fácil","detail":"Los terrenos del palacio son llanos, con algunos escalones en los patios. La Biblioteca Starfield cuenta con escaleras mecánicas y ascensores accesibles en sus cuatro plantas."}]},{"title":"Cuando el tiempo y las estaciones cambian","icon":"cloud-sun","iconBg":"bg-ámbar-50/80","iconColor":"text-amber-600","items":[{"label":"Cerezos en flor a principios de abril","detail":"Las murallas de la fortaleza están flanqueadas por cerezos: a principios de abril se abre la mejor ventana fotográfica. El alquiler de hanbok en el palacio garantiza las mejores fotos del día."},{"label":"Calor estival en julio y agosto","detail":"La muralla de la fortaleza tiene sombra escasa. El día se orienta hacia los caminos sombreados del Pueblo Folclórico y el tiempo interior en Starfield. La hidratación es fundamental."},{"label":"Frío invernal de diciembre a febrero","detail":"El paseo por la muralla se acorta en los días fríos; los horarios de las actuaciones interiores en el Pueblo Folclórico se reducen. Starfield se convierte en la parada naturalmente más larga."}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"Qué está incluido","preview":"Transporte en autobús de ida y vuelta desde Seúl, guía turístico de habla inglesa, Fortaleza Hwaseong de Suwon…","content":["Transporte en autobús de ida y vuelta desde Seúl, guía turístico de habla inglesa, entrada a la Fortaleza Hwaseong de Suwon, entrada al Palacio Haenggung de Hwaseong, entrada al Pueblo Folclórico Coreano.","No incluido: comidas, bebidas, experiencias opcionales en el pueblo tradicional (alquiler de hanbok, tiro con arco), propinas.","La entrada a la Biblioteca Starfield es gratuita."]},{"id":"pickup","title":"Recogida y regreso","preview":"Estación de la Universidad Hongik (Salida 8) a las ≈08:00 o Estación de Myeongdong (Salida 2 o 4) a las ≈08:30.","content":["Estación de la Universidad Hongik (Salida 8) a las ≈08:00 o Estación de Myeongdong (Salida 2 o 4) a las ≈08:30.","Llegue con 10 minutos de antelación.","No hay recogida en hotel; solo puntos de encuentro.","No se puede acomodar a quienes lleguen tarde."]},{"id":"walking","title":"Caminata y terreno","preview":"Moderado.","content":["Moderado.","El paseo por la muralla de la fortaleza incluye escalones de piedra en pendiente y superficies irregulares — se recorre aproximadamente 1 km del circuito total de 5,7 km.","El Pueblo Tradicional es un amplio recinto al aire libre (≈99 hectáreas) pero llano.","La Biblioteca Starfield cuenta con escaleras y escaleras mecánicas entre plantas.","Es imprescindible llevar calzado cómodo para caminar."]},{"id":"what","title":"Qué vestir y qué llevar","preview":"Calzado cómodo cerrado, sombrero en verano, ropa en capas en…","content":["Calzado cómodo cerrado, sombrero en verano, ropa en capas en primavera/otoño, abrigo de invierno en invierno (las murallas de la fortaleza están expuestas al viento).","Cámara, agua y snacks ligeros.","Efectivo para el almuerzo y cualquier actividad opcional en el pueblo tradicional."]},{"id":"cancellation","title":"Cancelación","preview":"Cancelación gratuita hasta 24 horas antes del inicio del tour.","content":["Cancelación gratuita hasta 24 horas antes del inicio del tour.","Las cancelaciones el mismo día y las no presentaciones no son reembolsables."]},{"id":"children","title":"Niños y accesibilidad","preview":"Los niños son bienvenidos — el pueblo folclórico en particular es apto para familias, con espectáculos de caballos…","content":["Los niños son bienvenidos — el pueblo folclórico en particular es apto para familias, con espectáculos de caballos y juegos tradicionales.","Los cochecitos pueden circular por los caminos principales de Haenggung y del pueblo folclórico.","El recorrido por la muralla de la fortaleza tiene escaleras y no es apto para cochecitos.","Accesibilidad limitada para usuarios de silla de ruedas en los tramos de la fortaleza."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Ver notas estacionales"},"tomorrow":{"temp":"—","label":"Ver notas estacionales"},"_seasonalSummary":"Suwon and Yongin track Seoul''s weather closely (about 30 km south). Plan for hot, humid summers and cold, dry winters; spring and autumn are the most comfortable.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"5–22°C","notes":"Cherry blossoms along the fortress wall in early–mid April."},{"season":"Summer (Jun–Aug)","range":"22–32°C","notes":"Hot and humid; bring sun protection and water."},{"season":"Autumn (Sep–Nov)","range":"8–22°C","notes":"Best season — clear skies, mild temperatures."},{"season":"Winter (Dec–Feb)","range":"-5 to 6°C","notes":"Cold winds on the fortress wall; library is indoors and warm."}]},"seasonalVariations":[{"season":"Primavera","description":"Flores de cerezo a lo largo de la muralla de Hwaseong y en el pueblo folclórico; gran Festival Cultural de Suwon Hwaseong a principios de otoño."},{"season":"Verano","description":"Festival del agua en el pueblo folclórico; iluminación nocturna en Haenggung en noches seleccionadas."},{"season":"Otoño","description":"Follaje de arce a lo largo de la muralla de la fortaleza, temporada alta del Pueblo Folclórico Coreano para bodas tradicionales y demostraciones de cosecha."},{"season":"Invierno","description":"La nieve sobre la muralla de la fortaleza es una de las fotografías más icónicas de Corea; el pueblo folclórico celebra costumbres invernales (kimjang, fuegos de ondol)."}],"bookingTrustItems":[{"icon":"check-circle","title":"Operador local autorizado","description":"Operador de tours coreano autorizado con seguro completo","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Especialistas en rutas","description":"Itinerario personalizado, no un recorrido genérico","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Tamaño de grupo seleccionado","description":"Dimensionado adecuadamente para la ruta","iconBg":"bg-amber-50/80 *(clase CSS — sin traducción)*","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Inmediatamente","title":"Confirmación instantánea","detail":"Confirmación de reserva con resumen del itinerario"},{"timing":"12 horas antes","title":"Recordatorio de 12 horas","detail":"Actualización del clima y posibles ajustes de ruta"},{"timing":"La tarde anterior","title":"Información final de recogida","detail":"Hora exacta de recogida y contacto del conductor"},{"timing":"La mañana del tour","title":"Notas de ruta del día","detail":"Resumen matutino basado en las condiciones en tiempo real"},{"timing":"Durante el tour","title":"Consejos parada por parada","detail":"Orientación en tiempo real en cada lugar"},{"timing":"Después del tour","title":"Asistencia posterior al tour","detail":"Seguimiento y recomendaciones"}],"staticQuestions":[{"id":"q1","question":"¿Están incluidas las entradas?","answer":"Sí — Las entradas a la Fortaleza Hwaseong de Suwon, el Palacio Hwaseong Haenggung y la Aldea Folclórica Coreana están todas incluidas. La Biblioteca Starfield es gratuita para todos. El alquiler de hanbok, el tiro con arco u otros complementos opcionales de la aldea folclórica corren por cuenta del visitante."},{"id":"q2","question":"¿Está incluido el almuerzo?","answer":"No. El almuerzo generalmente se toma durante el tiempo libre en el patio de comidas de Starfield Suwon (gran variedad, ₩10,000–₩20,000) o en un pequeño restaurante de Suwon cerca de la fortaleza (galbi o pollo al estilo Suwon)."},{"id":"q3","question":"¿Qué parte de la muralla de la fortaleza recorremos a pie?","answer":"Aproximadamente 1 km del circuito de 5,7 km, generalmente el tramo entre Janganmun y Hwaseomun, incluyendo algunos baluartes y un montículo de señales. El circuito completo lleva más de 3 horas y no está contemplado en este itinerario."},{"id":"q4","question":"¿Vale la pena dedicar una hora completa a la Biblioteca Starfield?","answer":"Sí, para los visitantes primerizos — es un atractivo arquitectónico por sí solo. El tiempo libre también está pensado para almorzar tarde, tomar un café o explorar el centro comercial Starfield Suwon (el emblemático Starfield de segunda generación de Corea, inaugurado en enero de 2024)."},{"id":"q5","question":"¿Puedo alquilar un hanbok en el Pueblo Folk?","answer":"Sí, el alquiler de hanbok está disponible en el lugar por un cargo adicional (normalmente ₩10,000–₩20,000 por 1–2 horas). Usar hanbok también te otorga descuentos en actividades de experiencias tradicionales. El guía puede indicarte dónde está el puesto de alquiler."},{"id":"q6","question":"¿Hay alguna diferencia con el tour de Suwon + Waujeongsa?","answer":"Sí. Este tour incluye el Pueblo Folk Coreano (un importante sitio del patrimonio) y utiliza la Biblioteca Starfield como parada moderna. La versión de Waujeongsa prescinde del Pueblo Folk y lo reemplaza con el templo del Buda gigante en Yongin. Elige este si te importa más la profundidad patrimonial; la versión de Waujeongsa si te importa más la escultura budista."},{"id":"first-time","question":"¿Es esta una buena opción para los visitantes primerizos a Suwon y Yongin?","answer":"Sí — una excelente primera opción para los viajeros que desean visitar un sitio de la UNESCO (Fortaleza Hwaseong), un pueblo patrimonial (Pueblo Folk Coreano), un palacio Joseon (Haenggung) y un espacio fotográfico contemporáneo (Biblioteca Starfield) en un solo día. El itinerario cubre cuatro facetas contrastantes de la cultura coreana sin repetir los palacios del centro de Seúl. Geográficamente, la ruta se mantiene en el corredor Suwon-Yongin."},{"id":"walking","question":"¿Es difícil caminar?","answer":"Día con mucha caminata, ≈4-5 km en total. La muralla de Hwaseong es la sección más exigente: 1 km a pie entre Janganmun y Hwaseomun, con pendientes pronunciadas, escaleras en las puertas y superficies históricas irregulares. El Pueblo Folk Coreano añade ≈2 horas de caminata por senderos llanos a ligeramente inclinados (más de 270 casas distribuidas). El Palacio Haenggung y la Biblioteca Starfield tienen superficies interiores y de patio de fácil acceso. Zapatos cómodos imprescindibles."},{"id":"family","question":"¿Es este tour adecuado para familias?","answer":"Sí, para familias cuyos hijos puedan aguantar un día de 10 horas con varias paradas con bastante caminata. El Pueblo Folk es el punto culminante para las familias — más de 270 casas tradicionales, espectáculos ecuestres, locaciones de rodaje de K-dramas y bodas tradicionales los fines de semana. El alquiler de hanbok en el Palacio Haenggung es un divertido momento fotográfico (y permite la entrada gratuita a la fortaleza para quienes vistan hanbok). Los cochecitos son difíciles de usar en la muralla, pero no hay problema en Starfield ni en el Pueblo Folk."},{"id":"seniors","question":"¿Pueden unirse cómodamente los adultos mayores?","answer":"Recomendado únicamente para personas mayores activas que se sientan cómodas con escaleras y terreno irregular. La muralla de la fortaleza es la sección más difícil — las pendientes pronunciadas y las escaleras hacen que algunos tramos sean complicados para sillas de ruedas. Las personas mayores pueden recorrer los tramos más fáciles de la muralla y omitir los puestos de mando. Los caminos del Pueblo Folk son llanos a ligeramente inclinados, transitables para la mayoría. Haenggung es mayormente llano. Starfield cuenta con escaleras mecánicas y ascensores totalmente accesibles."},{"id":"children","question":"¿Cuál es la edad mínima recomendada?","answer":"Lo más adecuado es a partir de los 10 años aproximadamente — el día implica una caminata considerable por la muralla de la fortaleza (superficies irregulares), una exploración activa del Pueblo Folk y una jornada larga en general. Los niños más pequeños pueden unirse con portabebés, pero el kilómetro de caminata por la muralla más las 2 horas en el Pueblo Folk pueden agotar a los niños de 6 a 9 años. Los espectáculos ecuestres y las actuaciones tradicionales en el Pueblo Folk son muy populares entre los niños de mayor edad."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id se resuelve en tiempo de ejecución desde Supabase / env; no forma parte del JSONB estático.","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:00","name":"Estación Hongik Univ. (Salida 8)","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"time":"08:30","name":"Estación Myeongdong (Salida 2 o 4)","type":"station","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"Estación Hongik Univ. (Salida 8)","type":"station","lat":37.55753,"lng":126.92447},{"order":2,"name":"Estación Myeongdong (Salida 4)","type":"station","lat":37.56099,"lng":126.98619}],"notes":["Llega 10 minutos antes. No se podrá atender a quienes lleguen tarde y no se realizarán reembolsos."]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-folk-village-starfield-library","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"coach","duration_hours":10,"region_tags":["gyeonggi_suwon","gyeonggi_goyang"],"theme_tags":["unesco","fortress","folk_village","modern_landmark","mixed_culture"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","korean_folk_village","starfield_library_suwon"],"pace_level":0.6,"walking_level":0.8,"scenic_level":0.8,"photo_level":1,"culture_level":1,"relax_level":0.6,"first_time_fit":0.95,"family_fit":0.85,"senior_fit":0.7,"couple_fit":0.85,"solo_traveler_fit":0.85,"active_traveler_fit":0.5,"adu